// Funkcja tłumaczenia — fallback na PL jeśli brak klucza EN
// Użycie: t('klucz') lub t('klucz').replace('{x}', wartość)
function t(key) {
  return T[LANG][key] || T['pl'][key] || key;
}

// Ustaw język i zapisz — wywoływana z lang pickera
function setLang(l) {
  LANG = l;
  localStorage.setItem('gtg_lang', l);
  _syncLangButtons();
  applyLang();
}

// applyLang — aktualizuje wszystkie elementy Fazy 1 i 2 na stronie
// Wywoływana po zmianie języka i przy każdym wejściu do menu
function applyLang() {
  // data-i18n — kafelki, przyciski menu
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (T[LANG][key] !== undefined) el.textContent = T[LANG][key];
  });
  // ── Faza 1: Splash ──
  _setTxt('splash-tap-lbl', 'splash_tap');
  // ── Faza 1: Saves ──
  _setTxt('saves-ph-title', 'saves_title');
  _setTxt('saves-ph-back',  'saves_back');
  // ── Faza 1: Setup ──
  _setTxt('setup-ph-title',    'setup_title');
  _setTxt('setup-ph-back',     'setup_back');
  _setTxt('setup-mgr-label',   'setup_mgr_label');
  _setTxt('setup-club-hdr',    'setup_club_hdr');
  _setTxt('setup-club-change', 'setup_club_change');
  _setTxt('setup-ovr-label',   'setup_ovr_label');
  _setTxt('setup-budget-label','setup_budget_label');
  _setTxt('setup-league-label','setup_league_label');
  _setTxt('setup-league-val',  'setup_league_val');
  _setTxt('setup-reroll-hint', 'setup_reroll_hint');
  _setTxt('setup-start-btn',   'setup_start');
  _updateRerollBtn();
  // ── Faza 1: Modal nowej gry ──
  _setTxt('ng-title',   'ng_title');
  _setTxt('ng-confirm', 'ng_confirm');
  _setTxt('ng-cancel',  'ng_cancel');
  const ngBody = document.getElementById('ng-body');
  if (ngBody) ngBody.innerHTML = t('ng_body').replace('\n','<br>');
  const mgrInput = document.getElementById('mgr-name');
  if (mgrInput && !mgrInput._userEdited) mgrInput.placeholder = t('setup_mgr_default');
  // ── Faza 2: Modale ogólne ──
  _setTxt('modal-save-title',    'modal_save_title');
  _setTxt('modal-save-cancel',   'modal_cancel');
  _setTxt('modal-contract-cancel','modal_cancel');
  _setTxt('mc-submit-btn',       'modal_contract_offer');
  _setTxt('modal-buy-title',     'modal_buy_title');
  _setTxt('modal-buy-cancel',    'modal_cancel');
  _setTxt('modal-buy-confirm',   'modal_buy_confirm');
  _setTxt('modal-sell-title',    'modal_sell_title');
  _setTxt('modal-sell-cancel',   'modal_cancel');
  _setTxt('modal-sell-confirm',  'modal_sell_confirm');
  // ── Faza 2: Nagłówek gry — odświeżamy jeśli gra aktywna ──
  if(typeof G !== 'undefined' && G && G.myClub) {
    updateHdr();
    // ── Faza 3: Odśwież otwarte panele ──
    if(document.getElementById('p-squad')&&document.getElementById('p-squad').classList.contains('open'))fillSquad();
    if(document.getElementById('p-transfers')&&document.getElementById('p-transfers').classList.contains('open'))fillTransfers();
    if(document.getElementById('p-training')&&document.getElementById('p-training').classList.contains('open'))fillTraining();
    // ── Faza 4a: Mecz, Tabela, Puchar ──
    if(document.getElementById('p-match')&&document.getElementById('p-match').classList.contains('open'))fillMatch();
    if(document.getElementById('p-tactics')&&document.getElementById('p-tactics').classList.contains('open')){fillTactics();fillTacSquad();}
    if(document.getElementById('p-table')&&document.getElementById('p-table').classList.contains('open'))fillTable();
    if(document.getElementById('p-cup')&&document.getElementById('p-cup').classList.contains('open'))fillCup();
    // ── Sesja 1: FA + karta zawodnika ──
    if(document.getElementById('p-freeagents')&&document.getElementById('p-freeagents').classList.contains('open')){const _crisis=checkSquadCrisis&&checkSquadCrisis();if(_crisis)openFACrisis(_crisis);}
    if(document.getElementById('p-player')&&document.getElementById('p-player').classList.contains('open')&&window._plrId){const _pp=G&&G.players&&G.players.find(x=>x.id===window._plrId);if(_pp)showPlayer(_pp);}
    // Tytuł panelu squad
    _setTxt('squad-panel-title','squad_title');
    _setTxt('squad-back-btn','modal_back');
    // Newsy — zakładki re-renderujemy
    if(typeof renderNews==='function')renderNews();
  }
}

function _setTxt(id, key) {
  const el = document.getElementById(id);
  if (el) el.textContent = t(key);
}

function _updateRerollBtn() {
  const btn = document.getElementById('btn-reroll');
  const lbl = document.getElementById('reroll-left-lbl');
  if (lbl) lbl.textContent = LANG === 'en' ? 'left' : 'pozostały';
  // Cały tekst przycisku poza licznikiem (licznik zostaje jako span)
  // Aktualizujemy tylko teksty wokół spana #reroll-left
  if (btn) {
    const n = document.getElementById('reroll-left');
    const count = n ? n.textContent : '3';
    btn.innerHTML = t('setup_reroll').replace('{n}', '<span id="reroll-left">' + count + '</span> <span id="reroll-left-lbl">' + (LANG === 'en' ? 'left' : 'pozostały') + '</span>');
  }
}

// Pokaż lang picker — jednorazowo przy pierwszym uruchomieniu (brak zapisu w localStorage)
function showLangPicker(onDone) {
  const overlay = document.createElement('div');
  overlay.id = 'lang-picker-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:#000;z-index:99999;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:28px;';
  overlay.innerHTML =
    '<div style="font-family:\'Press Start 2P\',monospace;font-size:var(--fs-hero);color:var(--am);text-shadow:3px 3px 0 #7a5c00;text-align:center;line-height:1.8">GRASSROOTS<br>TO GLORY</div>'+
    '<div style="font-family:VT323,monospace;font-size:var(--fs-display);color:var(--gr);letter-spacing:2px;text-align:center">SELECT LANGUAGE / WYBIERZ JĘZYK</div>'+
    '<div style="display:flex;gap:16px">'+
      '<button id="lang-btn-pl" onclick="pickLang(\'pl\')" style="font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);padding:14px 22px;background:var(--tb);border:2px solid var(--am);color:var(--am);cursor:pointer;letter-spacing:1px">🇵🇱 POLSKI</button>'+
      '<button id="lang-btn-en" onclick="pickLang(\'en\')" style="font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);padding:14px 22px;background:var(--tb);border:1px solid var(--gr);color:var(--gr);cursor:pointer;letter-spacing:1px">🇬🇧 ENGLISH</button>'+
    '</div>'+
    '<div style="font-family:VT323,monospace;font-size:var(--fs-body);color:#1a3d1a;letter-spacing:1px">v1.0</div>';
  document.body.appendChild(overlay);
  window._langPickerCallback = onDone || null;
}

function pickLang(l) {
  setLang(l); // setLang już woła applyLang
  const overlay = document.getElementById('lang-picker-overlay');
  if (overlay) overlay.remove();
  if (window._langPickerCallback) { window._langPickerCallback(); window._langPickerCallback = null; }
}

