// buildNamePool — używa FIRST/LAST lub FIRST_EN/LAST_EN zależnie od LANG
// (nadpisuje oryginalne buildNamePool poniżej — WAŻNE: ta definicja musi być PRZED oryginalną)
// Oryginalna funkcja buildNamePool() zostaje w kodzie, ale wywołujemy nową przez buildNamePoolI18n()
function buildNamePoolI18n() {
  const firstArr = LANG === 'en' ? FIRST_EN : FIRST;
  const lastArr  = LANG === 'en' ? LAST_EN  : LAST;
  const pool = [];
  const used = new Set();
  const allCombos = [];
  for (const f of firstArr) {
    for (const l of lastArr) {
      allCombos.push(f + ' ' + l);
    }
  }
  for (let i = allCombos.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [allCombos[i], allCombos[j]] = [allCombos[j], allCombos[i]];
  }
  for (const name of allCombos) {
    if (!used.has(name)) { used.add(name); pool.push(name); }
    if (pool.length >= 2000) break;
  }
  return pool;
}

// Funkcja pomocnicza — zwraca odpowiednią pulę klubów zależnie od LANG
function getClubsPool() {
  return LANG === 'en' ? CLUBS_POOL_EN : CLUBS_POOL;
}

// Kliknięcie splash screena — przy pierwszym uruchomieniu pokazuje lang picker
function onSplashTap() {
  if (!localStorage.getItem('gtg_lang')) {
    showLangPicker(function() { go('v-menu'); _syncLangButtons(); applyLang(); });
  } else {
    go('v-menu');
    _syncLangButtons();
    applyLang();
  }
}

// Synchronizuje wygląd przycisków lang toggle z aktualnym LANG
function _syncLangButtons() {
  const btnPl = document.getElementById('lang-btn-pl');
  const btnEn = document.getElementById('lang-btn-en');
  if (btnPl) { btnPl.style.borderWidth = LANG==='pl'?'2px':'1px'; btnPl.style.color = LANG==='pl'?'var(--am)':'var(--gr)'; }
  if (btnEn) { btnEn.style.borderWidth = LANG==='en'?'2px':'1px'; btnEn.style.color = LANG==='en'?'var(--am)':'var(--gr)'; }
}

