function getModuleLvl(key){return(G.stadium&&G.stadium.modules&&G.stadium.modules[key])||0;}
function checkModuleReq(req){
  if(!req)return{ok:true};
  const cap=(G.stadium&&G.stadium.capacity)||200;
  const rep=(G.reputation)||0;
  if(req.capacity&&cap<req.capacity)return{ok:false,msg:'Wymaga '+req.capacity.toLocaleString('pl-PL')+' miejsc'};
  if(req.rep&&rep<req.rep)return{ok:false,msg:'Wymaga reputacji '+req.rep};
  if(req.light&&getModuleLvl('light')<req.light)return{ok:false,msg:'Wymaga Oświetlenia L'+req.light};
  return{ok:true};
}
// Auto-refresh paska budowy gdy tab rozbudowa jest aktywny
setInterval(function(){
  if(!G||!G.stadium||!G.stadium.building)return;
  const el=document.getElementById('stad-rozbudowa');
  if(!el||!el.classList.contains('on'))return;
  const bar=el.querySelector('.stad-build-bar');
  if(!bar)return;
  const tw=G.stadium.building.totalWeeks||1;
  const pct=Math.min(100,Math.round((1-(G.stadium.building.weeksLeft/tw))*100));
  const done=tw-G.stadium.building.weeksLeft;
  bar.querySelector('.stad-bar-fill').style.width=pct+'%';
  bar.querySelector('.stad-bar-left').textContent='Tydzień '+done+' / '+tw;
  bar.querySelector('.stad-bar-right').textContent=pct+'% — zostało '+G.stadium.building.weeksLeft+' tyg.';
},500);

function stadTab(tab,btn){
  document.querySelectorAll('#p-stadium .tab-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  ['przeglad','rozbudowa','moduly','historia'].forEach(t=>{
    const el=document.getElementById('stad-'+t);if(el)el.classList.remove('on');
  });
  const el=document.getElementById('stad-'+tab);if(el)el.classList.add('on');
  if(tab==='przeglad')renderStadPrzeglad();
  else if(tab==='rozbudowa')renderStadRozbudowa();
  else if(tab==='historia')renderStadHistoria();
}
function drawStadiumTopDown(cap,freq,modules){
  // Deterministyczny seed na podstawie pojemności — te same dane = ten sam układ kibiców
  let _seed=cap*1000+Math.round(freq*100);
  function rng(){_seed=(_seed*16807+0)%2147483647;return(_seed-1)/2147483646;}

  const W=280,H=200;
  const tribW=cap<400?8:cap<800?14:cap<1500?20:cap<3000?26:cap<6000?32:38;
  const px=70-tribW,py=50-tribW,pw=140+tribW*2,ph=100+tribW*2;
  const dotSz=3;
  const hasGastro=modules&&modules.gastro>0;
  const hasVip=modules&&modules.vip>0;
  const hasLight=modules&&modules.light>0;
  const hasShop=modules&&modules.shop>0;
  const hasBoard=modules&&modules.board>0;

  // Kolory kibiców: zielone + złote (barwy klubu) + szare (puste)
  const fanCols=['#4caf50cc','#4caf5099','#ffc10799','#2d7d3299','#66bb6acc'];
  const emptCol='#1a3d1a55';

  let s=`<svg viewBox="0 0 ${W} ${H}" width="100%" style="display:block;background:#060f06;">`;
  s+=`<defs>
    <linearGradient id="pitchTD" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#1e5c1e"/>
      <stop offset="50%" stop-color="#2d7d32"/>
      <stop offset="100%" stop-color="#1e5c1e"/>
    </linearGradient>
    <filter id="glowTD"><feGaussianBlur stdDeviation="2" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
  </defs>`;

  // Tło trybun (beton)
  s+=`<rect x="${px}" y="${py}" width="${pw}" height="${ph}" fill="#0d200d" rx="3"/>`;

  // Piksele kibiców — North
  for(let row=0;row<Math.min(tribW,20);row+=dotSz){
    const cols=Math.floor(pw/dotSz);
    for(let d=0;d<cols;d++){
      const filled=rng()<freq;
      const col=filled?fanCols[Math.floor(rng()*fanCols.length)]:emptCol;
      s+=`<rect x="${px+d*dotSz}" y="${py+row}" width="${dotSz-.5}" height="${dotSz-.5}" fill="${col}" rx=".4"/>`;
    }
  }
  // South
  for(let row=0;row<Math.min(tribW,20);row+=dotSz){
    const cols=Math.floor(pw/dotSz);
    for(let d=0;d<cols;d++){
      const filled=rng()<freq;
      const col=filled?fanCols[Math.floor(rng()*fanCols.length)]:emptCol;
      s+=`<rect x="${px+d*dotSz}" y="${py+ph-Math.min(tribW,20)+row}" width="${dotSz-.5}" height="${dotSz-.5}" fill="${col}" rx=".4"/>`;
    }
  }
  // West & East
  const rowsH=Math.floor(100/dotSz);
  for(let row=0;row<Math.min(tribW,20);row+=dotSz){
    for(let d=0;d<rowsH;d++){
      const fW=rng()<freq;const fE=rng()<freq;
      const cW=fW?fanCols[Math.floor(rng()*fanCols.length)]:emptCol;
      const cE=fE?fanCols[Math.floor(rng()*fanCols.length)]:emptCol;
      s+=`<rect x="${px+row}" y="${50+d*dotSz}" width="${dotSz-.5}" height="${dotSz-.5}" fill="${cW}" rx=".4"/>`;
      s+=`<rect x="${px+pw-Math.min(tribW,20)+row}" y="${50+d*dotSz}" width="${dotSz-.5}" height="${dotSz-.5}" fill="${cE}" rx=".4"/>`;
    }
  }

  // Boisko — pasy naprzemienne
  s+=`<rect x="70" y="50" width="140" height="100" fill="url(#pitchTD)" rx="2"/>`;
  for(let i=0;i<7;i++) s+=`<rect x="${70+i*20}" y="50" width="20" height="100" fill="${i%2===0?'#1e5c1ecc':'#245c2466'}"/>`;

  // Linie boiska
  s+=`<rect x="70" y="50" width="140" height="100" fill="none" stroke="#ffffff55" stroke-width=".9"/>`;
  s+=`<line x1="140" y1="50" x2="140" y2="150" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<circle cx="140" cy="100" r="18" fill="none" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<circle cx="140" cy="100" r="1.5" fill="#ffffff66"/>`;
  s+=`<rect x="70" y="74" width="22" height="52" fill="none" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<rect x="70" y="85" width="10" height="30" fill="none" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<rect x="188" y="74" width="22" height="52" fill="none" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<rect x="200" y="85" width="10" height="30" fill="none" stroke="#ffffff44" stroke-width=".8"/>`;
  s+=`<rect x="65" y="91" width="5" height="18" fill="none" stroke="#ffffffaa" stroke-width="1.2"/>`;
  s+=`<rect x="210" y="91" width="5" height="18" fill="none" stroke="#ffffffaa" stroke-width="1.2"/>`;

  // MODUŁY — ikonki w narożnikach
  if(hasGastro) s+=`<text x="3" y="13" font-size="11" opacity=".9">🍔</text>`;
  if(hasVip)    s+=`<text x="${W-16}" y="13" font-size="11" opacity=".9">🎭</text>`;
  if(hasLight)  s+=`<text x="3" y="${H-3}" font-size="11" opacity=".9">💡</text>`;
  if(hasShop)   s+=`<text x="${W-16}" y="${H-3}" font-size="11" opacity=".9">🛍</text>`;
  if(hasBoard){
    // Tablica wynikowa nad boiskiem
    s+=`<rect x="115" y="34" width="50" height="13" fill="#000" stroke="#ffc107" stroke-width=".8" rx="1"/>`;
    s+=`<text x="140" y="44" font-family="VT323,monospace" font-size="9" fill="#ffc107" text-anchor="middle" letter-spacing="1">📺 TABLICA</text>`;
  }

  // Słupy oświetlenia (cztery narożniki) gdy moduł light
  if(hasLight){
    [[px-2,py-2],[px+pw+2,py-2],[px-2,py+ph+2],[px+pw+2,py+ph+2]].forEach(([lx,ly])=>{
      s+=`<circle cx="${lx}" cy="${ly}" r="3" fill="#ffc10788" filter="url(#glowTD)"/>`;
    });
  }

  // Frekwencja label
  const viewers=Math.round(cap*freq);
  s+=`<text x="${W/2}" y="${H-2}" font-family="VT323,monospace" font-size="11" fill="#4caf5077" text-anchor="middle">${viewers.toLocaleString('pl-PL')} widzów</text>`;

  s+=`</svg>`;
  return s;
}

function fillStadium(){
  if(!G)return;
  if(!G.stadium)G.stadium={capacity:200,shopMult:1,adsMult:1,vipWeekly:0,gasBonus:0,modules:{},hist:[]};
  // Odśwież aktywny tab stadionu
  const activeTab=document.querySelector('#p-stadium .tab-pane.on');
  if(activeTab){
    if(activeTab.id==='stad-rozbudowa')renderStadRozbudowa();
    else if(activeTab.id==='stad-moduly')renderStadModuly();
    else renderStadPrzeglad();
  } else renderStadPrzeglad();
}
function renderStadPrzeglad(){
  const el=document.getElementById('stad-przeglad');if(!el||!G)return;
  const s=G.stadium;const lvl=G.myLeague||8;
  const cap=s.capacity||200;const freq=(G.frequency||50)/100;
  const tp=FIN.ticketPrice[lvl]||5;
  const gasB=s.gasBonus||0;
  const perMatch=Math.round(cap*freq*tp*(1+gasB));
  const perWeek=Math.round(perMatch/2);
  const maxCap=STAD.maxCap[lvl]||2000;
  const inBuild=s.building;
  const activeMods=Object.entries(STAD_MODULES).filter(([k])=>getModuleLvl(k)>0);
  el.innerHTML=
    drawStadiumTopDown(cap,freq,s.modules||{})+
    '<div style="background:var(--tb);border:1px solid var(--gl);border-top:none;padding:7px 10px;margin-bottom:8px">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-meta);color:var(--am);margin-bottom:6px">'+(G.myClub&&G.myClub.n||'Stadion')+'</div>'+
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-family:VT323,monospace;font-size:var(--fs-dense)">'+
        '<div><div style="color:var(--gr)">Pojemność</div><div style="color:var(--wh);font-size:var(--fs-meta)">'+cap.toLocaleString('pl-PL')+' miejsc</div></div>'+
        '<div><div style="color:var(--gr)">Max ('+LEAGUE_NAMES[lvl]+')</div><div style="color:var(--gr)">'+maxCap.toLocaleString('pl-PL')+'</div></div>'+
        '<div><div style="color:var(--gr)">Frekwencja</div><div style="color:var(--gb)">'+(G.frequency||50)+'%</div></div>'+
        '<div><div style="color:var(--gr)">Widzów/mecz</div><div style="color:var(--wh)">~'+Math.round(cap*freq).toLocaleString('pl-PL')+'</div></div>'+
        '<div><div style="color:var(--gr)">Cena biletu</div><div style="color:var(--am)">'+tp+' zł</div></div>'+
        '<div><div style="color:var(--gr)">Bilety/tyg</div><div style="color:var(--gb)">+'+fmt(perWeek)+'</div><div style="color:var(--gr);font-size:var(--fs-dense)">'+fmt(perMatch)+' zł/mecz</div></div>'+
      '</div>'+
    '</div>'+
    '<div style="background:#000;border:1px solid var(--gl);height:10px;margin-bottom:10px;position:relative">'+
      '<div style="height:100%;background:var(--gb);width:'+Math.min(100,Math.round(cap/maxCap*100))+'%"></div>'+
      '<div style="position:absolute;right:4px;top:0;font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--wh)">'+Math.min(100,Math.round(cap/maxCap*100))+'%</div>'+
    '</div>'+
 
    (activeMods.length?
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb);margin-bottom:4px">AKTYWNE MODUŁY</div>'+
      activeMods.map(([k,m])=>'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:2px 0">'+m.icon+' '+m.name+' L'+getModuleLvl(k)+' — '+m.levels[getModuleLvl(k)-1].effect+'</div>').join('')+
      '<div style="margin-bottom:8px"></div>':'')+
    (!inBuild?'<button onclick="stadTab(\'rozbudowa\',document.querySelectorAll(\'#p-stadium .tab-btn\')[1])" style="width:100%;background:var(--am);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-body);padding:12px;cursor:pointer">ROZBUDUJ STADION</button>':'');
}
function renderStadRozbudowa(){
  const el=document.getElementById('stad-rozbudowa');if(!el||!G)return;
  const s=G.stadium;const lvl=G.myLeague||8;
  const cap=s.capacity||200;const maxCap=STAD.maxCap[lvl]||2000;
  // Pasek postępu budowy — zawsze na górze gdy trwa
  const buildBar=s.building?(()=>{
    const _tw=s.building.totalWeeks||s.building.weeksLeft||1;
    const pct=Math.min(100,Math.round((1-(s.building.weeksLeft/_tw))*100));
    const done=_tw-s.building.weeksLeft;
    return '<div class="stad-build-bar" style="background:#1a1000;border:2px solid var(--am);padding:10px 12px;margin-bottom:12px">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);margin-bottom:6px">🔨 W BUDOWIE: +'+s.building.seats.toLocaleString('pl-PL')+' miejsc</div>'+
      '<div style="background:#000;height:10px;border:1px solid var(--gl);margin-bottom:5px;position:relative">'+
        '<div class="stad-bar-fill" style="height:100%;background:var(--am);width:'+pct+'%;transition:width 0.3s"></div>'+
      '</div>'+
      '<div style="display:flex;justify-content:space-between;font-family:VT323,monospace;font-size:var(--fs-dense)">'+
        '<span class="stad-bar-left" style="color:var(--gr)">Tydzień '+done+' / '+_tw+'</span>'+
        '<span class="stad-bar-right" style="color:var(--am)">'+pct+'% — zostało '+s.building.weeksLeft+' tyg.</span>'+
      '</div>'+
    '</div>';
  })():'';
  if(cap>=maxCap){
    el.innerHTML='<div style="color:var(--gr);font-family:VT323,monospace;font-size:var(--fs-dense);padding:16px;text-align:center">Osiągnięto limit dla '+LEAGUE_NAMES[lvl]+'. Awansuj wyżej.</div>'+
      '<div class="fsec" style="margin:12px 0 8px">MODUŁY</div><div id="stad-rozb-moduly"></div>';
    _renderStadModulyInRozb();return;
  }
  const maxAdd=Math.min(2000,maxCap-cap);
  if(!window._stadAdd||window._stadAdd<100)window._stadAdd=100;
  window._stadAdd=Math.max(100,Math.min(maxAdd,window._stadAdd));
  const n=window._stadAdd;
  const cost=STAD.calcCost(cap,n);const weeks=STAD.buildTime(n);
  const newCap=cap+n;const tp=FIN.ticketPrice[lvl]||5;
  const freq=(G.frequency||50)/100;const gasB=s.gasBonus||0;
  const curBil=Math.round(cap*freq*tp*(1+gasB)/2);
  const newBil=Math.round(newCap*freq*tp*(1+gasB)/4);
  const canAfford=G.budget>=cost;
  el.innerHTML=
    buildBar+
    '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:8px">Pojemność: <span style="color:var(--wh)">'+cap.toLocaleString('pl-PL')+'</span> / Max: '+maxCap.toLocaleString('pl-PL')+'</div>'+
    '<div style="background:var(--tb);border:1px solid var(--gl);padding:7px 10px;margin-bottom:8px">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb);margin-bottom:8px">ILE MIEJSC DODAĆ?</div>'+
      '<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">'+
        '<button onclick="changeStadAdd(-100)" style="background:var(--gm);border:1px solid var(--gl);color:var(--wh);font-size:var(--fs-display);width:40px;height:40px;cursor:pointer">-</button>'+
        '<div style="flex:1;text-align:center;font-family:VT323,monospace;font-size:var(--fs-display);color:var(--am)">'+n.toLocaleString('pl-PL')+' miejsc</div>'+
        '<button onclick="changeStadAdd(100)" style="background:var(--gm);border:1px solid var(--gl);color:var(--wh);font-size:var(--fs-display);width:40px;height:40px;cursor:pointer">+</button>'+
      '</div>'+
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-family:VT323,monospace;font-size:var(--fs-dense);margin-bottom:10px">'+
        '<div><div style="color:var(--gr)">Nowa pojemność</div><div style="color:var(--wh)">'+newCap.toLocaleString('pl-PL')+' miejsc</div></div>'+
        '<div><div style="color:var(--gr)">Koszt</div><div style="color:'+(canAfford?'var(--am)':'var(--rd)')+'">'+fmt(cost)+'</div></div>'+
        '<div><div style="color:var(--gr)">Czas budowy</div><div style="color:var(--wh)">'+weeks+' tyg.</div></div>'+
        '<div><div style="color:var(--gr)">Bilety/tyg po</div><div style="color:var(--gb)">+'+fmt(newBil)+' (+'+fmt(newBil-curBil)+')</div></div>'+
      '</div>'+
      (s.building?
        '<button disabled style="width:100%;background:var(--gr);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:12px;cursor:not-allowed;opacity:0.5">BUDOWA W TOKU...</button>'
      :canAfford?
        '<button onclick="startBuild()" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:12px;cursor:pointer">ROZPOCZNIJ BUDOWĘ — '+fmt(cost)+'</button>'
      :'<div style="background:#3d0000;border:1px solid var(--rd);padding:8px;text-align:center;font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">Brakuje '+fmt(cost-G.budget)+'</div>')+
    '</div>'+
    '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">Koszt/miejsce: '+(cap<500?'80':cap<2000?'150':cap<5000?'280':cap<15000?'500':'900')+' zł</div>'+
    '<div class="fsec" style="margin:14px 0 8px">MODUŁY</div>'+
    '<div id="stad-rozb-moduly"></div>';
  _renderStadModulyInRozb();
}
function renderStadModuly(){
  const el=document.getElementById('stad-moduly');if(!el||!G)return;
  if(!G.stadium.modules)G.stadium.modules={};
  const mb=G.stadium.modulBuilding;
  // Pasek budowy aktywnego modułu
  let buildingHtml='';
  if(mb){
    const mod=STAD_MODULES[mb.key];
    const pct=Math.round((1-(mb.weeksLeft/mb.totalWeeks))*100);
    buildingHtml='<div style="background:#1a1000;border:2px solid var(--am);padding:10px 12px;margin-bottom:10px">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);margin-bottom:4px">🔨 W BUDOWIE: '+(mod?mod.icon+' '+mod.name:'?')+' L'+(mb.lvl+1)+'</div>'+
      '<div style="background:#000;height:8px;border:1px solid var(--gl);margin-bottom:4px">'+
        '<div style="height:100%;background:var(--am);width:'+pct+'%"></div>'+
      '</div>'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">Pozostało: '+mb.weeksLeft+' tyg. z '+mb.totalWeeks+'</div>'+
    '</div>';
  }
  el.innerHTML=buildingHtml+Object.entries(STAD_MODULES).map(([key,mod])=>{
    const lvl=getModuleLvl(key);const maxLvl=mod.levels.length;
    const next=mod.levels[lvl];const isMax=lvl>=maxLvl;
    const isBuilding=mb&&mb.key===key;
    const otherBuilding=mb&&mb.key!==key;
    const req=next?checkModuleReq(next.req):{ok:false,msg:''};
    const canAfford=next&&G.budget>=next.cost;
    const prog=Array.from({length:maxLvl},(_,i)=>'<div style="flex:1;height:5px;margin:0 1px;background:'+(i<lvl?'var(--gb)':isBuilding&&i===lvl?'var(--am)':'#0d1f0d')+'"></div>').join('');
    return '<div style="background:var(--tb);border:1px solid '+(isBuilding?'var(--am)':lvl>0?'var(--gb)':'var(--gl)')+';padding:10px 12px;margin-bottom:8px">'+
      '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'+
        '<span style="font-size:var(--fs-display)">'+mod.icon+'</span>'+
        '<div style="flex:1"><div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--wh)">'+mod.name+'</div>'+
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">L'+lvl+'/'+maxLvl+'</div></div>'+
        (isBuilding?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am)">🔨 '+mb.weeksLeft+' tyg.</div>':
         lvl>0?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">L'+lvl+'</div>':'')+
      '</div>'+
      '<div style="display:flex;margin-bottom:6px">'+prog+'</div>'+
      (lvl>0?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb);margin-bottom:4px">'+mod.levels[lvl-1].effect+'</div>':'')+
      (isMax?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);text-align:center">MAX</div>':
       isBuilding?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am)">W budowie: L'+(lvl+1)+' — '+next.effect+'</div>':
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:4px">L'+(lvl+1)+': '+next.effect+' • '+fmt(next.cost)+' • '+(next.buildWeeks||1)+' tyg.</div>'+
        (otherBuilding?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">🔒 Inny moduł w budowie</div>':
         !req.ok?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">'+req.msg+'</div>':
         !canAfford?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">Brakuje '+fmt(next.cost-G.budget)+'</div>':
         '<button onclick="buyModule(\''+key+'\')" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">BUDUJ — '+fmt(next.cost)+' • '+(next.buildWeeks||1)+' tyg.</button>')
      )+
    '</div>';
  }).join('');
}
function renderStadHistoria(){
  const el=document.getElementById('stad-historia');if(!el||!G)return;
  const hist=(G.stadium&&G.stadium.hist)||[];
  el.innerHTML=hist.length?
    '<table style="width:100%;border-collapse:collapse;font-family:VT323,monospace;font-size:var(--fs-dense)">'+
    '<thead><tr>'+
      '<th style="text-align:left;padding:4px 6px;color:var(--gr);border-bottom:1px solid var(--gl)">S/T</th>'+
      '<th style="text-align:left;padding:4px 6px;color:var(--gr);border-bottom:1px solid var(--gl)">INWESTYCJA</th>'+
      '<th style="text-align:right;padding:4px 6px;color:var(--rd);border-bottom:1px solid var(--gl)">KOSZT</th>'+
    '</tr></thead><tbody>'+
    hist.slice().reverse().map(h=>
      '<tr style="border-bottom:1px solid #0d1f0d">'+
        '<td style="padding:4px 6px;color:var(--gr)">S'+h.season+' T'+h.week+'</td>'+
        '<td style="padding:4px 6px;color:var(--wh)">'+(h.seats?'+'+h.seats.toLocaleString('pl-PL')+' miejsc':h.module||'?')+'</td>'+
        '<td style="text-align:right;padding:4px 6px;color:var(--rd)">-'+fmt(h.cost)+'</td>'+
      '</tr>'
    ).join('')+'</tbody></table>'
  :'<div style="color:var(--gr);font-family:VT323,monospace;font-size:var(--fs-dense);padding:12px">Brak historii inwestycji</div>';
}
function changeStadAdd(delta){
  const s=G.stadium||{};const cap=s.capacity||200;
  const lvl=G.myLeague||8;const maxAdd=Math.min(1000,STAD.maxCap[lvl]-cap);
  window._stadAdd=Math.max(100,Math.min(maxAdd,(window._stadAdd||100)+delta));
  renderStadRozbudowa();
}
function _renderStadModulyInRozb(){
  const mEl=document.getElementById('stad-rozb-moduly');if(!mEl||!G)return;
  if(!G.stadium.modules)G.stadium.modules={};
  const mb=G.stadium.modulBuilding;

  let html='';
  Object.entries(STAD_MODULES).forEach(([key,mod])=>{
    const lvl=getModuleLvl(key);
    const maxLvl=mod.levels.length;
    const next=mod.levels[lvl];
    const isMax=lvl>=maxLvl;
    const isBuilding=mb&&mb.key===key;
    const otherBuilding=mb&&mb.key!==key;
    const req=next?checkModuleReq(next.req):{ok:false,msg:''};
    const canAfford=next&&G.budget>=next.cost;

    // Pasek poziomów
    const dots=Array.from({length:maxLvl},(_,i)=>{
      let col=i<lvl?'var(--gb)':(isBuilding&&i===lvl?'var(--am)':'#1a2a1a');
      return '<div style="flex:1;height:6px;border-radius:2px;margin:0 1px;background:'+col+'"></div>';
    }).join('');

    // Kolor ramki
    const border=isBuilding?'var(--am)':isMax?'#555':lvl>0?'var(--gb)':'var(--gl)';

    // Aktualny efekt (jeśli coś jest)
    const curEffect=lvl>0?mod.levels[lvl-1].effect:'—';

    // Blok statusu / akcji
    let actionHtml='';
    if(isMax){
      actionHtml='<div style="text-align:center;color:var(--am);font-family:VT323,monospace;font-size:var(--fs-dense);padding:4px 0">✓ MAX</div>';
    } else if(isBuilding){
      const pct=Math.round((1-(mb.weeksLeft/mb.totalWeeks))*100);
      actionHtml=
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);margin-bottom:4px">🔨 Buduje się L'+(lvl+1)+' — pozostało '+mb.weeksLeft+' tyg.</div>'+
        '<div style="background:#000;height:5px;border:1px solid var(--gl)"><div style="height:100%;background:var(--am);width:'+pct+'%"></div></div>';
    } else if(otherBuilding){
      actionHtml='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">🔒 Inny moduł w budowie</div>';
    } else if(!req.ok){
      actionHtml='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">🔒 '+req.msg+'</div>';
    } else if(!canAfford){
      actionHtml='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">Brakuje '+fmt(next.cost-G.budget)+'</div>';
    } else {
      actionHtml='<button onclick="buyModule(\''+key+'\')" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:7px;cursor:pointer;letter-spacing:1px">BUDUJ L'+(lvl+1)+' — '+fmt(next.cost)+' • '+(next.buildWeeks||1)+' tyg.</button>';
    }

    html+=
      '<div style="background:var(--tb);border:1px solid '+border+';border-radius:3px;padding:10px 12px;margin-bottom:8px">'+
        // Nagłówek: ikona + nazwa + poziom
        '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'+
          '<span style="font-size:var(--fs-display);line-height:1">'+mod.icon+'</span>'+
          '<div style="flex:1">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-meta);color:var(--wh);letter-spacing:1px">'+mod.name+'</div>'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">'+
              (isMax?'MAX':'L'+lvl+'/'+maxLvl+(next?' • następny: '+next.effect:''))+
            '</div>'+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);text-align:right;color:'+(isMax?'var(--am)':'var(--gr)')+'">'+
            (lvl>0?'<div style="color:var(--gb)">'+curEffect+'</div>':'')+
          '</div>'+
        '</div>'+
        // Pasek poziomów
        '<div style="display:flex;margin-bottom:8px">'+dots+'</div>'+
        // Akcja
        actionHtml+
      '</div>';
  });
  mEl.innerHTML=html;
}
function renderStadModuly(){_renderStadModulyInRozb();}
function startBuild(){
  if(!G||!G.stadium)return;
  const s=G.stadium;const cap=s.capacity||200;
  if(s.building){notif('Budowa już trwa! Poczekaj na zakończenie.','err');return;}
  const lvl=G.myLeague||8;const maxAdd=Math.min(1000,STAD.maxCap[lvl]-cap);
  const n=Math.max(100,Math.min(maxAdd,window._stadAdd||100));
  const cost=STAD.calcCost(cap,n);const weeks=STAD.buildTime(n);
  if(G.budget<cost){notif('Za mało środków!','err');return;}
  G.budget-=cost;
  if(!G.fin.hist)G.fin.hist=[];
  G.fin.hist.push({w:G.week,inc:0,cost:cost,bal:G.budget,season:G.season,note:'Rozbudowa stadionu: +'+n.toLocaleString('pl-PL')+' miejsc'});
  s.building={seats:n,weeksLeft:weeks,totalWeeks:weeks,cost};
  addNews(t('news_stad_build_started').replace('{n}',n.toLocaleString('pl-PL')).replace('{cost}',fmt(cost)).replace('{weeks}',weeks),'club');
  notif('Budowa rozpoczęta! Gotowe za '+weeks+' tygodni.','ok');
  window._stadAdd=100;fillStadium();
}
function buyModule(key){
  if(!G||!G.stadium)return;
  if(!G.stadium.modules)G.stadium.modules={};
  const mod=STAD_MODULES[key];if(!mod)return;
  const lvl=getModuleLvl(key);
  if(lvl>=mod.levels.length){notif('Maksymalny poziom!','err');return;}
  const next=mod.levels[lvl];
  const req=checkModuleReq(next.req);
  if(!req.ok){notif(req.msg,'err');return;}
  if(G.budget<next.cost){notif('Za mało środków!','err');return;}
  if(G.stadium.modulBuilding){notif('Inny moduł jest w budowie!','err');return;}
  G.budget-=next.cost;
  if(!G.fin.hist)G.fin.hist=[];
  G.fin.hist.push({w:G.week,inc:0,cost:next.cost,bal:G.budget,season:G.season,note:mod.icon+' Moduł: '+mod.name+' L'+(lvl+1)});
  const weeks=next.buildWeeks||1;
  G.stadium.modulBuilding={key,lvl,next,cost:next.cost,weeksLeft:weeks,totalWeeks:weeks};
  addNews(t('news_stad_module_started').replace('{icon}',mod.icon).replace('{name}',mod.name).replace('{lvl}',lvl+1).replace('{weeks}',weeks).replace('{cost}',fmt(next.cost)),'club');
  notif(mod.name+' L'+(lvl+1)+' — budowa '+weeks+' tyg.','ok');
  renderStadModuly();
}


// ══════════════════════════════════════════════════════════
// ETAP 4 — SPONSORZY + PRAWA TV (w panelu Finanse)
// ══════════════════════════════════════════════════════════
function finTab(tab,btn){
  document.querySelectorAll('#p-finance .tab-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  ['przeglad','kontrakty','historia','sezony','zarzad'].forEach(t=>{
    const el=document.getElementById('fin-'+t);if(el)el.classList.remove('on');
  });
  const el=document.getElementById('fin-'+tab);if(el)el.classList.add('on');
  if(tab==='przeglad')renderFinPrzeglad();
  else if(tab==='kontrakty')renderFinKontrakty();
  else if(tab==='historia')renderFinHistoria();
  else if(tab==='sezony')renderFinSezony();
  else if(tab==='zarzad')renderFinZarzad();
}

function renderFinZarzad(){
  const el=document.getElementById('fin-zarzad');if(!el||!G)return;
  if(!G.board)G.board={mainGoal:null,optGoal:null,goalsHistory:[]};
  const b=G.board;
  // --- sub-tabs wewnątrz zarząd ---
  const activeInner=el.dataset.inner||'cele';
  const mkTab=(id,label)=>`<button onclick="finZarzadInner('${id}',this)" style="flex:1;padding:8px 4px;background:none;border:none;border-bottom:2px solid ${activeInner===id?'var(--am)':'transparent'};font-family:\x27Press Start 2P\x27,monospace;font-size:var(--fs-micro);color:${activeInner===id?'var(--am)':'var(--gr)'};cursor:pointer">${label}</button>`;
  el.innerHTML=`<div style="display:flex;border-bottom:1px solid var(--gl);margin-bottom:10px">${mkTab('cele','CELE')}${mkTab('historia','HISTORIA')}</div><div id="fin-zarzad-inner" style="padding:0 2px"></div>`;
  renderFinZarzadInner(activeInner);
}
function finZarzadInner(tab,btn){
  const el=document.getElementById('fin-zarzad');if(!el)return;
  el.dataset.inner=tab;
  el.querySelectorAll('button').forEach(b=>{b.style.borderBottomColor='transparent';b.style.color='var(--gr)';});
  btn.style.borderBottomColor='var(--am)';btn.style.color='var(--am)';
  renderFinZarzadInner(tab);
}
function renderFinZarzadInner(tab){
  // Tymczasowo podmień target dla renderBoardCele/Historia na fin-zarzad-inner
  const inner=document.getElementById('fin-zarzad-inner');if(!inner)return;
  if(tab==='cele'){
    // Użyj board-cele jako bufor, potem przepisz
    const buf=document.getElementById('board-cele');
    if(!buf){inner.innerHTML='<div style="color:var(--gr);font-family:VT323,monospace;padding:12px;font-size:var(--fs-body)">Błąd: brak bufora zarządu.</div>';return;}
    renderBoardCele();
    inner.innerHTML=buf.innerHTML;
  } else {
    const buf=document.getElementById('board-historia');
    if(!buf){inner.innerHTML='<div style="color:var(--gr);font-family:VT323,monospace;padding:12px;font-size:var(--fs-body)">Błąd: brak bufora historii zarządu.</div>';return;}
    renderBoardHistoria();
    inner.innerHTML=buf.innerHTML;
  }
}

function renderFinPrzeglad(){
  const el=document.getElementById('fin-przeglad');if(!el||!G)return;
  const inc=calcWeeklyIncome();
  const lvl=G.myLeague||8;
  const pos=[...G.standing].sort((a,b)=>b.pts-a.pts||(b.gf-b.ga)-(a.gf-a.ga)).findIndex(s=>parseInt(s.cid)===parseInt(G.myClubId))+1;
  const bonusArr=(FIN.bonus&&FIN.bonus[lvl])||[];
  const expBonus=bonusArr[pos-1]||0;
  const sponsorInc=(G.contracts&&G.contracts.shirt?G.contracts.shirt.weekly:0)+
                   (G.contracts&&G.contracts.stadium?G.contracts.stadium.weekly:0)+
                   (G.contracts&&G.contracts.naming?G.contracts.naming.weekly:0);
  const tvInc=(G.contracts&&G.contracts.tv?G.contracts.tv.weekly:0)||inc.tv;
  const totalIncWeekly=inc.total+sponsorInc+(tvInc-inc.tv);
  const curCap=(G.stadium&&G.stadium.capacity)||200;
  const curMaint=Math.round(curCap*1000*0.005/4.3);
  const tcCost=tcLevel()>0?tcUpkeep(tcLevel()-1):0;
  const acadCost=G.fin.academyUpkeep||0;
  const salaries=G.fin.salaries||0;

  // Grupuj fin.hist po miesiącach (co 4 tygodnie od T3: M1=T3-T6, M2=T7-T10 itd.)
  // Miesiąc = Math.ceil((week-2)/4)
  function weekToMonth(w){return Math.max(1,Math.ceil(w/4));}
  const curMonth=weekToMonth(G.week);
  const hist=(G.fin.hist||[]).filter(h=>(h.season||1)===G.season);
  const transfers=(G.fin.transfers||[]).filter(t=>t.season===G.season);

  // Zbierz miesiące które mamy dane
  // monthNums uwzględnia też miesiące z transferów (nie tylko z hist)
  const monthNums=[...new Set([
    ...hist.map(h=>weekToMonth(h.w)),
    ...transfers.map(t=>weekToMonth(t.week||1))
  ])].sort((a,b)=>b-a).slice(0,6);
  if(!monthNums.includes(curMonth))monthNums.unshift(curMonth);
  monthNums.sort((a,b)=>b-a);

  function monthData(m){
    const w0=(m-1)*4+1; const w1=m*4; // T zakres miesiąca (M1=T1-T4, M2=T5-T8 itd.)
    const rows=hist.filter(h=>h.w>=w0&&h.w<=w1);
    const trRows=transfers.filter(t=>t.week>=w0&&t.week<=w1);
    const regInc=rows.filter(h=>!h.note).reduce((s,h)=>s+(h.inc||0),0);
    const salPaid=rows.filter(h=>!h.note&&h.costSalary>0).reduce((s,h)=>s+(h.costSalary||0),0);
    const maintPaid=rows.filter(h=>!h.note).reduce((s,h)=>s+(h.costMaint||0)+(h.costTC||0)+(h.costAcad||0),0);
    // Zdarzenia z fin.hist z note — ale wykluczamy SPR:/KUP: bo te są już w fin.transfers
    const nonTrRows=rows.filter(h=>h.note&&!h.note.startsWith('SPR:')&&!h.note.startsWith('KUP:'));
    const evtInc=nonTrRows.reduce((s,h)=>s+(h.inc||0),0);
    const evtCost=nonTrRows.reduce((s,h)=>s+(h.cost||0),0);
    const trSellInc=trRows.filter(t=>t.type==='sell').reduce((s,t)=>s+(t.val||0),0);
    const trBuyCost=trRows.filter(t=>t.type==='buy').reduce((s,t)=>s+(t.val||t.fee||0),0);
    const totalInc=regInc+evtInc+trSellInc;
    const totalCost=salPaid+maintPaid+evtCost+trBuyCost;
    const events=[
      ...nonTrRows.map(h=>({lbl:h.note,inc:h.inc||0,cost:h.cost||0})),
      ...trRows.filter(t=>t.type==='sell').map(t=>({lbl:'SPR: '+t.name,inc:t.val||0,cost:0})),
      ...trRows.filter(t=>t.type==='buy').map(t=>({lbl:'KUP: '+t.name,inc:0,cost:t.val||t.fee||0}))
    ];
    return{w0,w1,regInc,salPaid,maintPaid,evtInc,evtCost,trSellInc,trBuyCost,totalInc,totalCost,net:totalInc-totalCost,events};
  }

  // Jeśli brak danych historycznych (wczesna gra) — szacuj z aktualnych stawek
  function estimateMonth(m){
    const isCur=m===curMonth;
    const w0e=(m-1)*4+1; const w1e=m*4;
    const weeksIn=isCur?Math.max(1,G.week-w0e+1):4;
    // W szacunku nie uwzględniaj biletów — mecze są nieregularne i nieznane
    const _wIncLocal=calcWeeklyIncome();
    const _wIncNoTickets=totalIncWeekly-(_wIncLocal.tickets||0);
    const regInc=_wIncNoTickets*weeksIn;
    const salPaid=salaries;
    const maintPaid=(curMaint+tcCost+acadCost)*weeksIn;
    // Transfery z fin.transfers
    const trRowsE=transfers.filter(t=>t.week>=w0e&&t.week<=w1e);
    const trSellE=trRowsE.filter(t=>t.type==='sell').reduce((s,t)=>s+(t.val||0),0);
    const trBuyE=trRowsE.filter(t=>t.type==='buy').reduce((s,t)=>s+(t.val||t.fee||0),0);
    // Zdarzenia jednorazowe z fin.hist (budowa stadionu, bonus podpisania, kronika itp.)
    const histRowsE=hist.filter(h=>h.note&&h.w>=w0e&&h.w<=w1e
      &&!h.note.startsWith('SPR:')&&!h.note.startsWith('KUP:'));
    const evtIncE=histRowsE.reduce((s,h)=>s+(h.inc||0),0);
    const evtCostE=histRowsE.reduce((s,h)=>s+(h.cost||0),0);
    const eventsE=[
      ...histRowsE.map(h=>({lbl:h.note,inc:h.inc||0,cost:h.cost||0})),
      ...trRowsE.filter(t=>t.type==='sell').map(t=>({lbl:'SPR: '+t.name,inc:t.val||0,cost:0})),
      ...trRowsE.filter(t=>t.type==='buy').map(t=>({lbl:'KUP: '+t.name,inc:0,cost:t.val||t.fee||0}))
    ];
    // Dodaj niezaksięgowane bilety z bieżącego tygodnia (przed advWeek)
    const _pendingTickets=isCur?(G.fin.tickets||0):0;
    const regIncFinal=regInc+_pendingTickets;
    const totalInc=regIncFinal+trSellE+evtIncE;
    const totalCost=salPaid+maintPaid+trBuyE+evtCostE;
    return{w0:w0e,w1:w1e,regInc:regIncFinal,salPaid,maintPaid,evtInc:evtIncE+trSellE,evtCost:evtCostE+trBuyE,trSellInc:trSellE,trBuyCost:trBuyE,totalInc,totalCost,net:totalInc-totalCost,events:eventsE,estimated:true};
  }

  // Donut dla bieżącego miesiąca
  const curData=hist.filter(h=>weekToMonth(h.w)===curMonth&&!h.note).length>0
    ?monthData(curMonth):estimateMonth(curMonth);
  const donutInc=curData.totalInc; const donutCost=curData.totalCost;
  const donutTotal=donutInc+donutCost||1;
  const CIRC=2*Math.PI*34; // obwód r=34
  const incArc=Math.round(CIRC*donutInc/donutTotal*10)/10;
  const costArc=Math.round(CIRC*donutCost/donutTotal*10)/10;
  const netSign=curData.net>=0;

  // Bilans całego sezonu
  const allHist=hist;
  const allTr=transfers;
  // Wyklucz SPR:/KUP: z fin.hist bo te same transfery są już w fin.transfers
  const seasonInc=allHist.filter(h=>!h.note||(!h.note.startsWith('SPR:')&&!h.note.startsWith('KUP:'))).reduce((s,h)=>s+(h.inc||0),0)+allTr.filter(t=>t.type==='sell').reduce((s,t)=>s+(t.val||0),0);
  const seasonCost=allHist.filter(h=>!h.note||(!h.note.startsWith('SPR:')&&!h.note.startsWith('KUP:'))).reduce((s,h)=>s+(h.cost||0),0)+allTr.filter(t=>t.type==='buy').reduce((s,t)=>s+(t.val||t.fee||0),0);

  // Render
  let html='';

  // Donut + legenda
  html+='<div class="fc-donut-wrap">';
  html+='<div class="fc-donut">';
  html+=`<svg width="90" height="90" viewBox="0 0 90 90">`;
  html+=`<circle cx="45" cy="45" r="34" fill="none" stroke="#122412" stroke-width="12"/>`;
  if(donutCost>0)html+=`<circle cx="45" cy="45" r="34" fill="none" stroke="#f44336" stroke-width="12" stroke-dasharray="${costArc} ${CIRC-costArc}" stroke-dashoffset="0" transform="rotate(-90 45 45)" opacity="0.85"/>`;
  if(donutInc>0)html+=`<circle cx="45" cy="45" r="34" fill="none" stroke="#4caf50" stroke-width="12" stroke-dasharray="${incArc} ${CIRC-incArc}" stroke-dashoffset="${-costArc}" transform="rotate(-90 45 45)" opacity="0.85"/>`;
  html+='</svg>';
  html+=`<div class="fc-donut-center"><div class="fc-donut-amt ${netSign?'pos':'neg'}">${netSign?'+':''}${fmt(curData.net)}</div><div class="fc-donut-lbl">MIE ${curMonth}<br>BILANS</div></div>`;
  html+='</div>';
  html+='<div class="fc-legend">';
  html+=`<div class="fc-leg"><span class="fc-leg-dot" style="background:var(--gb)"></span><span class="fc-leg-lbl">Przychód</span><span class="fc-leg-val pos">+${fmt(curData.totalInc)}</span></div>`;
  html+=`<div class="fc-leg"><span class="fc-leg-dot" style="background:var(--rd)"></span><span class="fc-leg-lbl">Koszty</span><span class="fc-leg-val neg">-${fmt(curData.totalCost)}</span></div>`;
  html+=`<div style="margin-top:5px;padding-top:5px;border-top:1px solid var(--gl);font-size:var(--fs-dense);color:var(--gr)">Stan: <span style="font-family:'Press Start 2P',monospace;font-size:var(--fs-h2);color:${G.budget>=0?'var(--gb)':'var(--rd)'}">${fmt(G.budget)}</span></div>`;
  html+='</div></div>';

  // Lista miesięcy
  html+='<div class="fsec" style="margin:0">MIESIĘCZNE — sezon '+G.season+'</div>';

  monthNums.forEach(function(m){
    const _mw0=(m-1)*4+1; const _mw1=m*4;
    const hasHistData=hist.filter(h=>weekToMonth(h.w)===m&&!h.note).length>0;
    const hasTrData=transfers.filter(t=>t.week>=_mw0&&t.week<=_mw1).length>0;
    const hasRealData=hasHistData||hasTrData;
    const d=hasHistData?monthData(m):estimateMonth(m);
    const isCur=m===curMonth;
    html+=`<div class="fc-month">`;
    html+=`<div class="fc-month-hdr">`;
    html+=`<span class="fc-month-name">${isCur?'\u25b6 ':'\u25c6 '}MIE ${m} (T${d.w0}\u2013T${d.w1})${isCur?' BIER\u0104CY':''}${d.estimated?' \u2248':''}</span>`;
    
    html+='</div>';
    // Rozbicie przychodów regularnych z calcWeeklyIncome (bieżące stawki)
    const _wInc=calcWeeklyIncome();
    const _weeksInMonth=d.w1-d.w0+1;
    // Dla bieżącego miesiąca: skaluj przez tygodnie które minęły
    const _wScale=isCur?Math.max(1,G.week-d.w0+1):_weeksInMonth;
    const _estSpon=Math.round((_wInc.sponsors||0)*_wScale);
    const _estContr=Math.round((_wInc.contracts||0)*_wScale);
    const _estAds=Math.round((_wInc.ads||0)*_wScale);
    const _estTV=Math.round((_wInc.tv||0)*_wScale);
    const _estGad=Math.round((_wInc.gadgets||0)*_wScale);
    const _estVip=Math.round((_wInc.vip||0)*_wScale);
    // Bilety: z fin.hist (faktyczne) minus reszta
    const _estOther=_estSpon+_estContr+_estAds+_estTV+_estGad+_estVip;
    // Bilety z fin.hist (faktyczne) — sumujemy G.fin.tickets z historii tygodniowej
    // fin.hist.inc zawiera: sponsorzy+kontrakty+reklamy+TV+gadżety+VIP+bilety
    // Bilety = inc - (sponsorzy+kontrakty+reklamy+TV+gadżety+VIP) per tydzień
    let _ticketsEst=0;
    if(!d.estimated){
      // Dla zakończonych tygodni — czytaj z fin.hist
      const _histWeeks=hist.filter(h=>!h.note&&weekToMonth(h.w)===(d.w0<=2?1:Math.ceil(d.w0/4)));
      const _wIncForTicket=calcWeeklyIncome();
      const _nonTicketPerWeek=(_wIncForTicket.sponsors||0)+(_wIncForTicket.contracts||0)+
        (_wIncForTicket.ads||0)+(_wIncForTicket.tv||0)+(_wIncForTicket.gadgets||0)+(_wIncForTicket.vip||0);
      _histWeeks.forEach(function(h){
        const _t=Math.max(0,(h.inc||0)-_nonTicketPerWeek);
        _ticketsEst+=_t;
      });
      // Dodaj niezaksięgowane bilety bieżącego tygodnia
      _ticketsEst+=G.fin.tickets||0;
    } else {
      // Szacunek — bilety z G.fin.tickets (niezaksięgowane)
      _ticketsEst=G.fin.tickets||0;
    }
    html+=`<div class="fc-month-body">`;
    html+=`<div class="fc-mrow" style="border-bottom:1px solid #0a1f0a;margin-bottom:2px"><span class="fc-mrow-lbl" style="color:var(--wh)">Przychody regularne</span><span class="fc-mrow-val pos">+${fmt(d.regInc)}</span></div>`;
    if(_estSpon>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">Sponsorzy</span><span class="fc-mrow-val pos">+${fmt(_estSpon)}</span></div>`;
    if(_estContr>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">Kontrakty</span><span class="fc-mrow-val pos">+${fmt(_estContr)}</span></div>`;
    if(_estAds>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">Reklamy</span><span class="fc-mrow-val pos">+${fmt(_estAds)}</span></div>`;
    if(_estTV>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">TV</span><span class="fc-mrow-val pos">+${fmt(_estTV)}</span></div>`;
    if(_ticketsEst>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">Bilety (mecze dom.)</span><span class="fc-mrow-val pos">+${fmt(_ticketsEst)}</span></div>`;
    if(_estGad>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">Gadżety</span><span class="fc-mrow-val pos">+${fmt(_estGad)}</span></div>`;
    if(_estVip>0)html+=`<div class="fc-mrow" style="padding-left:8px"><span class="fc-mrow-lbl">VIP</span><span class="fc-mrow-val pos">+${fmt(_estVip)}</span></div>`;
    if(d.salPaid>0)html+=`<div class="fc-mrow"><span class="fc-mrow-lbl">Pensje (wyp\u0142ata)</span><span class="fc-mrow-val neg">-${fmt(d.salPaid)}</span></div>`;
    if(d.maintPaid>0)html+=`<div class="fc-mrow"><span class="fc-mrow-lbl">Stadion+Centrum+Akad.</span><span class="fc-mrow-val neg">-${fmt(d.maintPaid)}</span></div>`;
    d.events.forEach(function(ev){
      html+=`<div class="fc-mrow event"><span class="fc-mrow-lbl event">${ev.lbl}</span><span class="fc-mrow-val ${ev.inc>0?'pos':'neg'}">${ev.inc>0?'+'+fmt(ev.inc):'-'+fmt(ev.cost)}</span></div>`;
    });
    html+=`<div class="fc-mrow total"><span class="fc-mrow-lbl">BILANS</span><span class="fc-mrow-val ${d.net>=0?'pos':'neg'}">${d.net>=0?'+':''}${fmt(d.net)}</span></div>`;
    html+='</div></div>';
  });

  // Pasek sezonu
  const seasonNet=seasonInc-seasonCost;
  html+='<div class="fc-season-bar">';
  html+=`<div><div class="fc-season-lbl">PRZYCHODY S${G.season}</div><div class="fc-season-val pos">+${fmt(seasonInc)}</div></div>`;
  html+=`<div style="text-align:center"><div class="fc-season-lbl">KOSZTY S${G.season}</div><div class="fc-season-val neg">-${fmt(seasonCost)}</div></div>`;
  html+=`<div style="text-align:right"><div class="fc-season-lbl">BILANS S${G.season}</div><div class="fc-season-val ${seasonNet>=0?'pos':'neg'}">${seasonNet>=0?'+':''}${fmt(seasonNet)}</div></div>`;
  html+='</div>';

  el.innerHTML=html;
}
function renderFinSezony(){
  const el=document.getElementById('fin-sezony');if(!el||!G)return;
  const cHist=G.cHist||[];
  const finHist=G.fin&&G.fin.hist||[];
  const finTr=G.fin&&G.fin.transfers||[];
  const LN={1:'Premier Division',2:'I Liga',3:'II Liga',4:'III Liga',5:'IV Liga',6:'V Liga',7:'VI Liga',8:'VII Liga'};

  function seasonFinData(s){
    const rows=finHist.filter(h=>(h.season||1)===s);
    const trs=finTr.filter(t=>t.season===s);
    if(!rows.length&&!trs.length)return null;
    const nonTr=rows.filter(h=>!h.note||(!h.note.startsWith('SPR:')&&!h.note.startsWith('KUP:')));
    const inc=nonTr.reduce((a,h)=>a+(h.inc||0),0)
              +trs.filter(t=>t.type==='sell').reduce((a,t)=>a+(t.val||0),0);
    const cost=nonTr.reduce((a,h)=>a+(h.cost||0),0)
               +trs.filter(t=>t.type==='buy').reduce((a,t)=>a+(t.val||t.fee||0),0);
    return{inc,cost,net:inc-cost};
  }

  const maxSeason=G.season||(cHist.length>0?Math.max(...cHist.map(c=>c.season)):1);
  const seasons=[];
  for(let s=1;s<=maxSeason;s++){
    const ch=cHist.find(c=>c.season===s);
    const fd=seasonFinData(s);
    seasons.push({s,ch,fd,isCur:s===G.season&&!G.seasonEnded});
  }
  if(!seasons.length){el.innerHTML='<div style="color:var(--gr);font-family:VT323,monospace;font-size:var(--fs-dense);padding:16px">Brak danych sezonowych.</div>';return;}

  const totInc=seasons.filter(r=>r.fd).reduce((a,r)=>a+(r.fd.inc||0),0);
  const totCost=seasons.filter(r=>r.fd).reduce((a,r)=>a+(r.fd.cost||0),0);
  const totNet=totInc-totCost;

  let html='';
  seasons.slice().reverse().forEach(function(r){
    const{s,ch,fd,isCur}=r;
    const leagueShort=ch?(LN[ch.leagueLevel]||ch.league||'?').replace('Premier Division','Premier Div.').replace(' Liga',' L.'):'?';
    const pos=ch?ch.pos:null;
    const isProm=pos&&pos<=2;
    const isRel=pos&&pos>14;
    const posStr=pos?(isProm?'<span style="color:#ffd700">'+pos+'. ★</span>':isRel?'<span style="color:var(--rd)">'+pos+'. ↓</span>':pos+'.'):' ?';
    const borderCol=isCur?'var(--am)':'var(--gl)';
    const bgCol=isCur?'#0a1a0a':'var(--gd)';

    // Pasek proporcji
    let incPct=50,costPct=50;
    if(fd&&(fd.inc+fd.cost)>0){
      incPct=Math.round(fd.inc/(fd.inc+fd.cost)*100);
      costPct=100-incPct;
    }
    const salStr=fd?'<span style="color:var(--gb)">+'+fmt(fd.inc)+'</span>':'<span style="color:var(--gr)">?</span>';
    const costStr=fd?'<span style="color:var(--rd)">-'+fmt(fd.cost)+'</span>':'<span style="color:var(--gr)">?</span>';
    const net=fd?fd.net:null;
    const netCol=net===null?'var(--gr)':net>=0?'var(--gb)':'var(--rd)';
    const netStr=net===null?'?':(net>=0?'+':'')+fmt(net);

    html+=`<div style="border-bottom:1px solid var(--gl);padding:8px 12px;background:${bgCol};border-left:3px solid ${borderCol}">`;
    // Nagłówek karty
    html+=`<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:5px">`;
    html+=`<span style="font-family:'Press Start 2P',monospace;font-size:var(--fs-h2);color:${isCur?'var(--am)':'var(--wh)'}">S${s}${isCur?' \u25c4':''}</span>`;
    html+=`<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">${leagueShort} \u2022 ${posStr}</span>`;
    html+='</div>';
    // Przychody / Koszty
    html+=`<div style="display:flex;justify-content:space-between;font-family:VT323,monospace;font-size:var(--fs-dense);margin-bottom:3px">`;
    html+=`<span>\u25b2 Przychody: ${salStr}</span>`;
    html+=`<span>\u25bc Koszty: ${costStr}</span>`;
    html+='</div>';
    // Pasek
    if(fd){
      html+=`<div style="height:7px;background:#0a150a;margin-bottom:4px;position:relative;overflow:hidden">`;
      html+=`<div style="position:absolute;left:0;height:100%;width:${incPct}%;background:var(--gb);opacity:0.85"></div>`;
      html+=`<div style="position:absolute;left:${incPct}%;height:100%;width:${costPct}%;background:var(--rd);opacity:0.75"></div>`;
      html+='</div>';
    } else {
      html+='<div style="height:7px;background:#0a150a;margin-bottom:4px"></div>';
    }
    // Saldo
    html+=`<div style="text-align:right;font-family:'Press Start 2P',monospace;font-size:var(--fs-h2);color:${netCol}">SALDO: ${netStr}</div>`;
    html+='</div>';
  });

  // ŁĄCZNIE
  const totNet2=totNet;
  html+=`<div style="background:var(--tb);padding:8px 12px;display:flex;justify-content:space-between;align-items:center;border-top:2px solid var(--gb)">`;
  html+=`<span style="font-family:'Press Start 2P',monospace;font-size:var(--fs-h2);color:var(--wh)">\u0141\u0104CZNIE</span>`;
  html+=`<div style="text-align:right;font-family:VT323,monospace;font-size:var(--fs-dense)">`;
  html+=`<div><span style="color:var(--gb)">+${fmt(totInc)}</span> / <span style="color:var(--rd)">-${fmt(totCost)}</span></div>`;
  html+=`<div style="font-family:'Press Start 2P',monospace;font-size:var(--fs-h2);color:${totNet2>=0?'var(--gb)':'var(--rd)'}">${totNet2>=0?'+':''}${fmt(totNet2)}</div>`;
  html+='</div></div>';
  html+='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:5px 12px 8px">\u2605 Przychody = regularne + premia + sprzeda\u017ce. Koszty = sta\u0142e + zakupy.</div>';

  el.innerHTML=html;
}
function renderFinKontrakty(){
  const el=document.getElementById('fin-kontrakty');if(!el||!G)return;
  if(!G.contracts)G.contracts={};
  const lvl=G.myLeague||8;
  const rep=G.reputation||30;
  const cap=(G.stadium&&G.stadium.capacity)||200;

  // Oblicz wartość oferty sponsorskiej na podstawie reputacji i ligi
  function sponsorOffer(slot){
    const base={shirt:{1:300000,2:150000,3:15000,4:5000,5:2000,6:800,7:300,8:150},
                stadium:{1:150000,2:75000,3:7500,4:2500,5:1000,6:400,7:150,8:80},
                naming:{1:600000,2:300000,3:30000,4:10000,5:4000,6:1500,7:0,8:0}};
    const b=(base[slot]&&base[slot][lvl])||0;
    const repMult=Math.max(0.8,Math.min(1.8,0.8+(rep||30)/1000*1.0));
    const raw=b*repMult;
    return raw<500?Math.round(raw/50)*50:Math.round(raw/500)*500;
  }

  // TV kontrakt wartość
  function tvOffer(){
    if(lvl>3&&!G.tvForced)return 0; // tylko od III Ligi
    const base={1:500000,2:150000,3:8000};
    const b=base[lvl]||0;
    return Math.round(b*(Math.max(0.5,rep/50))/100)*100;
  }

  // Wymagania
  const reqStadium=cap>=1000;
  const reqNaming=cap>=5000&&rep>=300;
  const reqTV=lvl<=3&&rep>=150;

  const sponsorTiers=[
    {minRep:0,  maxRep:49,  name:'Lokalny sklep',   color:'var(--gr)'},
    {minRep:50, maxRep:99,  name:'Regionalna firma', color:'var(--wh)'},
    {minRep:100,maxRep:199, name:'Krajowa marka',    color:'var(--am)'},
    {minRep:200,maxRep:399, name:'Duza korporacja',  color:'#4fc3f7'},
    {minRep:400,maxRep:699, name:'Sponsor premium',  color:'var(--gb)'},
    {minRep:700,maxRep:1000,name:'Globalny gigant',  color:'#ffd700'},
  ];
  const curRep=G.reputation||30;
  const curTier=sponsorTiers.find(t=>curRep>=t.minRep&&curRep<=t.maxRep)||sponsorTiers[0];
  const nextTier=sponsorTiers.find(t=>t.minRep>curRep)||null;

  function contractBox(slot,label,icon,req,reqMsg,weekly,active){
    const hasActive=G.contracts[slot]&&G.contracts[slot].weekly>0;
    const seasonsLeft=G.contracts[slot]?G.contracts[slot].seasonsLeft:0;
    return '<div style="background:var(--tb);border:1px solid '+(hasActive?'var(--gb)':'var(--gl)')+';padding:10px 12px;margin-bottom:8px">'+
      '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'+
        '<span style="font-size:var(--fs-display)">'+icon+'</span>'+
        '<div style="flex:1">'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--wh)">'+label+'</div>'+
          (hasActive?(function(){
            const _repMC=Math.max(0.8,Math.min(1.8,0.8+(G.reputation||30)/1000*1.0));
            const _actual=Math.round(G.contracts[slot].weekly*_repMC);
            const _base=G.contracts[slot].weekly;
            return '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">'+fmt(_base)+'/tyg • '+seasonsLeft+' sez.</div>'+
              '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am)">Faktycznie: <span style="color:var(--gb)">'+fmt(_actual)+'/tyg</span> (Rep ×'+_repMC.toFixed(2)+')</div>';
          })():
           '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">Brak kontraktu</div>')+
        '</div>'+
      '</div>'+
      (!hasActive?
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);margin-bottom:3px">'+
          'Sponsor: <span style="color:'+curTier.color+'">'+curTier.name+'</span>'+
          ' <span style="color:var(--gr)">(Rep. '+curTier.minRep+'–'+curTier.maxRep+')</span>'+
        '</div>'+
        (nextTier?
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:5px">'+
            'Następny: <span style="color:'+nextTier.color+'">'+nextTier.name+'</span>'+
            ' przy Rep. <span style="color:var(--am)">'+nextTier.minRep+'</span>'+
            ' <span style="color:var(--gr)">(brakuje '+(nextTier.minRep-curRep)+')</span>'+
          '</div>'
        :'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:#ffd700;margin-bottom:5px">Maksymalny poziom!</div>')
      :'')+
      (hasActive?
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">Aktywny kontrakt</div>'
      :!req?
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">'+reqMsg+'</div>'
      :weekly===0?
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">Brak ofert (za niska reputacja)</div>'
      :
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:5px">Oferta: <span style="color:var(--am)">+'+fmt(weekly)+'/tyg</span> • 1 sezon</div>'+
        '<button onclick="signContract(\''+slot+'\')" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">PODPISZ</button>'
      )+
    '</div>';
  }
  el.innerHTML=
    '<div class="fsec">SPONSORZY</div>'+
    contractBox('shirt','Sponsor koszulki','👕',true,'',sponsorOffer('shirt'),G.contracts.shirt)+
    contractBox('stadium','Sponsor stadionu','🏟️',reqStadium,'Wymaga stadionu 1000+ miejsc',sponsorOffer('stadium'),G.contracts.stadium)+
    contractBox('naming','Naming rights','💎',reqNaming,'Wymaga 5000+ miejsc i Rep. 300+',sponsorOffer('naming'),G.contracts.naming)+
    '<div class="fsec" style="margin-top:10px">PRAWA TELEWIZYJNE</div>'+
    contractBox('tv','Kontrakt TV','📺',reqTV,lvl>3?'Dostępne od III Ligi':'Wymaga Rep. 150+',tvOffer(),G.contracts.tv);
}

function signContract(slot){
  if(!G)return;
  if(!G.contracts)G.contracts={};
  const lvl=G.myLeague||8;const rep=G.reputation||30;
  const cap=(G.stadium&&G.stadium.capacity)||200;
  function getWeekly(s){
    const base={shirt:{1:300000,2:150000,3:15000,4:5000,5:2000,6:800,7:300,8:150},
                stadium:{1:150000,2:75000,3:7500,4:2500,5:1000,6:400,7:150,8:80},
                naming:{1:600000,2:300000,3:30000,4:10000,5:4000,6:1500,7:0,8:0},
                tv:{1:500000,2:150000,3:8000}};
    const b=(base[s]&&base[s][lvl])||0;
    const raw2=b*(Math.max(0.5,rep/50));
    return raw2<500?Math.round(raw2/50)*50:Math.round(raw2/500)*500;
  }
  const weekly=getWeekly(slot);
  if(weekly<=0){notif('Brak ofert!','err');return;}
  G.contracts[slot]={weekly,seasonsLeft:1,slot};
  addNews(t('news_sponsor_signed').replace('{slot}',({shirt:t('sponsor_slot_shirt'),stadium:t('sponsor_slot_stadium'),naming:t('sponsor_slot_naming'),tv:t('sponsor_slot_tv')}[slot]||slot)).replace('{val}',fmt(weekly)),'club');
  notif('Kontrakt podpisany: +'+fmt(weekly)+'/tyg!','ok');
  renderFinKontrakty();
}

function renderFinHistoria(){
  const el=document.getElementById('fin-historia');if(!el||!G)return;
  const weekly=(G.fin.hist||[]).filter(h=>!h.note&&(h.season||1)===G.season).slice().reverse();
  const allEvents={};
  (G.fin.hist||[]).filter(h=>h.note&&(h.season||1)===G.season).forEach(function(h){
    if(!allEvents[h.w])allEvents[h.w]=[];
    allEvents[h.w].push({lbl:h.note,inc:h.inc||0,cost:h.cost||0});
  });
  (G.fin.transfers||[]).filter(t=>t.season===G.season).forEach(function(t){
    const w=t.week||0;
    if(!allEvents[w])allEvents[w]=[];
    if(t.type==='sell')allEvents[w].push({lbl:'\u2794 SPR: '+t.name+(t.club?' \u2192'+t.club:''),inc:t.val||0,cost:0});
    else allEvents[w].push({lbl:'\u2794 KUP: '+t.name,inc:0,cost:t.val||t.fee||0});
  });

  if(!weekly.length){el.innerHTML='<div style="color:var(--gr);font-family:VT323,monospace;font-size:var(--fs-dense);padding:16px">Brak historii \u2014 zacznij sezon aby zobaczy\u0107 dane finansowe.</div>';return;}

  let html='<div style="font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);color:var(--gr);padding:6px 0 8px;letter-spacing:1px">SEZON '+G.season+' — '+weekly.length+' TYGODNI</div>';
  html+='<table style="width:100%;border-collapse:collapse;font-family:VT323,monospace;font-size:var(--fs-dense)">';
  html+='<thead><tr>';
  html+='<th style="text-align:left;padding:4px 5px;border-bottom:2px solid var(--gl);font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);color:var(--gr)">TYG</th>';
  html+='<th style="text-align:right;padding:4px 5px;border-bottom:2px solid var(--gl);font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);color:var(--gb)">PRZYCH.</th>';
  html+='<th style="text-align:right;padding:4px 5px;border-bottom:2px solid var(--gl);font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);color:var(--rd)">KOSZTY</th>';
  html+='<th style="text-align:right;padding:4px 5px;border-bottom:2px solid var(--gl);font-family:\'Press Start 2P\',monospace;font-size:var(--fs-h2);color:var(--am)">STAN</th>';
  html+='</tr></thead><tbody>';

  // Tygodnie z wpisami tygodniowymi + tygodnie ze zdarzeniami bez wpisu (np. transfer w T1 bez meczu)
  const weeklyByW={};
  weekly.forEach(function(h){weeklyByW[h.w]=h;});
  const eventOnlyWeeks=Object.keys(allEvents).map(Number).filter(w=>!weeklyByW[w]);
  const allWeeks=[...weekly.map(h=>h.w),...eventOnlyWeeks].sort((a,b)=>b-a);

  allWeeks.forEach(function(w){
    const h=weeklyByW[w];
    const hasSplit=h&&h.costSalary!==undefined;
    const isPayWeek=h&&hasSplit?h.costSalary>0:h&&(w%4===0&&h.cost>0);
    const totalCost=h&&h.cost||0;
    const rowBg=isPayWeek?'background:#1a0800':'';
    if(h){
      html+=`<tr style="${rowBg}">`;
      html+=`<td style="padding:4px 5px;color:var(--gr)">T${w}${isPayWeek?' <span style="color:var(--am)">\u2605</span>':''}</td>`;
      html+=`<td style="text-align:right;padding:4px 5px;color:var(--gb)">${h.inc?'+'+fmt(h.inc):'\u2014'}</td>`;
      html+=`<td style="text-align:right;padding:4px 5px;color:var(--rd)">${totalCost>0?'-'+fmt(totalCost):'\u2014'}</td>`;
      html+=`<td style="text-align:right;padding:4px 5px;color:var(--am)">${fmt(h.bal)}</td>`;
      html+='</tr>';
    }
    // Zdarzenia jednorazowe tego tygodnia
    (allEvents[w]||[]).forEach(function(ev){
      html+='<tr style="background:#080f08">';
      html+=`<td colspan="2" style="padding:2px 5px 2px 12px;color:var(--am);font-size:var(--fs-dense)">\u21b3 ${ev.lbl}</td>`;
      html+=`<td style="text-align:right;padding:2px 5px;font-size:var(--fs-dense);color:${ev.inc>0?'var(--gb)':'var(--rd)'}">${ev.inc>0?'+'+fmt(ev.inc):'-'+fmt(ev.cost)}</td>`;
      html+=`<td style="padding:2px 5px;color:var(--gr);text-align:right">\u2014</td>`;
      html+='</tr>';
    });
  });

  html+='</tbody></table>';
  html+='<div style="font-size:var(--fs-dense);color:var(--gr);padding:4px 0 8px;font-family:VT323,monospace">\u2605 = tydzie\u0144 wyp\u0142aty pensji (co 4 tyg.).</div>';
  el.innerHTML=html;
}

// ETAP 5 - AKADEMIA JUNIOROW
const ACADEMY={
  costBase: [150000, 450000, 1200000, 3600000, 12000000],
  upkBase:  [500,    2000,   6000,    18000,   55000],
  costMult: {1:5.0,2:3.0,3:1.8,4:1.2,5:0.8,6:0.5,7:0.35,8:0.25},
  upkMult:  {1:6.0,2:3.5,3:4.0,4:3.6,5:2.1,6:1.2,7:0.75,8:0.45},
  levels:[
    {cost:150000, upkeep:150,  perSeason:1, maxPot:60, ovrMin:18, buildWeeks:8,  name:'Podstawowa',   req:0},
    {cost:450000, upkeep:800,  perSeason:2, maxPot:72, ovrMin:22, buildWeeks:12, name:'Rozwinęta',   req:100},
    {cost:1200000,upkeep:2500, perSeason:3, maxPot:82, ovrMin:27, buildWeeks:20, name:'Zaawansowana', req:250},
    {cost:3600000,upkeep:8000, perSeason:5, maxPot:92, ovrMin:32, buildWeeks:32, name:'Elitarna',     req:500},
    {cost:12000000,upkeep:25000,perSeason:2,maxPot:99, ovrMin:38, buildWeeks:52, name:'Mistrzów',     req:800, ekstraOnly:true},
  ]
};
function acadCost(lvlIdx){
  const lg=G?G.myLeague||8:8;
  const m=ACADEMY.costMult[lg]||1;
  return Math.round((ACADEMY.costBase[lvlIdx]||ACADEMY.levels[lvlIdx].cost)*m/500)*500;
}
function acadUpkeep(lvlIdx){
  const lg=G?G.myLeague||8:8;
  const m=ACADEMY.upkMult[lg]||1;
  return Math.round((ACADEMY.upkBase[lvlIdx]||ACADEMY.levels[lvlIdx].upkeep)*m/50)*50;
}
const TRAINING_CENTER={
  costBase:[80000,350000,1200000],
  upkBase: [300,1200,4000],
  costMult:{1:5.0,2:3.0,3:1.8,4:1.2,5:0.8,6:0.5,7:0.35,8:0.25},
  upkMult: {1:6.0,2:3.5,3:4.0,4:3.6,5:2.1,6:1.2,7:0.75,8:0.45},
  changeCost:{0:5000,1:15000,2:40000},
  levels:[
    {name:'Podstawowe',  profiles:1,buildWeeks:4, req:{rep:0,  stad:0}},
    {name:'Zaawansowane',profiles:2,buildWeeks:8, req:{rep:150,stad:1000}},
    {name:'Elitarne',    profiles:3,buildWeeks:14,req:{rep:400,stad:5000}},
  ]
};
const TC_PROFILES=[
  {id:'kondycja',   icon:'[Kond]', name:'Kondycja',    attrBonus:{phy:1.5}, fatBonus:true,  posFilter:null,    effect:'Zmęczenie -2x szybciej, PHY +50%'},
  {id:'technika',   icon:'[Tech]', name:'Technika',    attrBonus:{tec:1.4,pas:1.4},         posFilter:null,    effect:'TEC i PAS +40% szybciej'},
  {id:'atak',       icon:'[Atk]',  name:'Atak',        attrBonus:{sht:1.5,tec:1.5},         posFilter:['NAP'], effect:'SHT i TEC +50% (NAP)'},
  {id:'obrona',     icon:'[Obr]',  name:'Obrona',      attrBonus:{def:1.5,men:1.5},         posFilter:['OBR','GK'], effect:'OBR i MEN +50% (OBR/GK)'},
  {id:'mentalnosc', icon:'[Men]',  name:'Mentalność',attrBonus:{men:1.6}, formBonus:3, posFilter:null,effect:'MEN +60%, Forma +3/tyg'},
  {id:'regeneracja',icon:'[Reg]',  name:'Regeneracja', injBonus:0.85, healBonus:0.75,       posFilter:null,    effect:'Kontuzje -15%, leczenie -25%'},
];
function tcCost(i){const lg=G?G.myLeague||8:8;return Math.round((TRAINING_CENTER.costBase[i]||80000)*(TRAINING_CENTER.costMult[lg]||1)/500)*500;}
function tcUpkeep(i){const lg=G?G.myLeague||8:8;return Math.round((TRAINING_CENTER.upkBase[i]||300)*(TRAINING_CENTER.upkMult[lg]||1)/50)*50;}
function tcLevel(){return(G&&G.trainingCenter&&G.trainingCenter.level)||0;}
function tcProfiles(){return(G&&G.trainingCenter&&G.trainingCenter.profiles)||[];}
function tcMaxProfiles(){const l=tcLevel();return l>0?TRAINING_CENTER.levels[l-1].profiles:0;}
function getAcadLvl(){return(G.academy&&G.academy.level)||0;}
function acadTab(tab,btn){
  document.querySelectorAll('#p-academy .tab-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  ['przeglad','wychowankowie'].forEach(t=>{const el=document.getElementById('acad-'+t);if(el)el.classList.remove('on');});
  const el=document.getElementById('acad-'+tab);if(el)el.classList.add('on');
  if(tab==='przeglad')renderAcadPrzeglad();
  else if(tab==='wychowankowie')renderAcadWychowankowie();
}
function fillAcademy(){
  if(!G)return;
  if(!G.academy)G.academy={level:0,prospects:[],hist:[]};
  renderAcadPrzeglad();
}
function renderAcadPrzeglad(){
  const el=document.getElementById('acad-przeglad');if(!el||!G)return;
  if(!G.academy)G.academy={level:0,prospects:[],hist:[]};
  const lvl=getAcadLvl();
  const acad=ACADEMY.levels[lvl-1];
  const prospects=(G.academy.prospects||[]).filter(p=>p.status==='pending');
  el.innerHTML=
    '<div style="background:var(--tb);border:1px solid '+(lvl>0?'var(--gb)':'var(--gl)')+';padding:12px;margin-bottom:10px">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-meta);color:var(--am);margin-bottom:6px">'+
        (lvl===0?'Brak Akademii':'Akademia '+acad.name+' (L'+lvl+')')+
      '</div>'+
      (lvl>0?
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-family:VT323,monospace;font-size:var(--fs-dense)">'+
          '<div><span style="color:var(--gr)">Juniorzy/sez: </span><span style="color:var(--gb)">'+acad.perSeason+'</span></div>'+
          '<div><span style="color:var(--gr)">Max pot: </span><span style="color:var(--am)">'+acad.maxPot+'</span></div>'+
          '<div><span style="color:var(--gr)">Utrzym/tyg: </span><span style="color:var(--rd)">-'+fmt(acadUpkeep(lvl-1))+'</span></div>'+
        '</div>'+
        (lvl<ACADEMY.levels.length?
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-top:6px">Nast. poziom: <span style="color:var(--am)">'+ACADEMY.levels[lvl].name+'</span> — <span style="color:var(--wh)">'+fmt(acadCost(lvl))+' zł</span>'+
          (ACADEMY.levels[lvl].req>0?' (Rep: '+ACADEMY.levels[lvl].req+')':'')+
          '</div>'
        :'')
      :'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">Zbuduj akademię aby co sezon pojawiał się utalentowany junior.</div>')+
    '</div>'+
    (prospects.length?
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);margin-bottom:6px">NOWI JUNIORZY</div>'+
      prospects.map(function(pr){
        var trLabel=pr.trainRate>=1.5?'🌟 Talent':pr.trainRate>=1.1?'⚡ Szybki':'📊 Normalny';
        var trCol=pr.trainRate>=1.5?'#00e676':pr.trainRate>=1.1?'var(--am)':'var(--wh)';
        var arch5=pr.archetype&&ARCHETYPE_META[pr.archetype]?ARCHETYPE_META[pr.archetype]:null;
        var ATTRS5=['tec','pas','sht','def','phy','men'];
        var ATTR_LBL5={tec:'TEC',pas:'PAS',sht:'SHT',def:'DEF',phy:'PHY',men:'MEN'};
        var barHtml5=ATTRS5.map(function(a){
          var archM5=arch5?arch5.mult[a]||1.0:1.0;
          var total5=parseFloat((pr.trainRate*archM5).toFixed(2));
          var pct5=Math.min(100,Math.round(total5*50));
          var isHigh5=archM5>1;
          var barCol5=isHigh5?(arch5?arch5.color:'var(--am)'):'var(--gl)';
          return '<div style="flex:1;text-align:center">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+(isHigh5?(arch5?arch5.color:'var(--am)'):'var(--gr)')+'">'+ATTR_LBL5[a]+'</div>'+
            '<div style="height:18px;background:#0a0f0a;margin:2px 0;position:relative">'+
              '<div style="position:absolute;bottom:0;left:0;right:0;height:'+pct5+'%;background:'+barCol5+';opacity:0.85"></div>'+
            '</div>'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+(isHigh5?(arch5?arch5.color:'var(--am)'):'var(--gr)')+'">×'+total5.toFixed(1)+'</div>'+
          '</div>';
        }).join('');
        return '<div style="background:#0d2b0d;border:1px solid var(--gb);padding:10px 12px;margin-bottom:6px">'+
          '<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:4px">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-meta);color:var(--wh)">🎓 '+pr.name+'</div>'+
            (arch5?'<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+arch5.color+';border:1px solid '+arch5.color+';padding:1px 5px">'+arch5.icon+' '+arch5.name+'</span>':'')+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:4px">'+
            (POS_SHORT[pr.pos]||pr.pos)+' • '+pr.age+'l • OVR '+pr.ovr+' • Pot: <span style="color:var(--am)">'+pr.potential+'</span>'+
          '</div>'+
          '<div style="background:#0a0f0a;border:1px solid var(--gl);padding:5px 8px;margin-bottom:6px">'+
            '<div style="display:flex;justify-content:space-between;margin-bottom:3px">'+
              '<div style="font-family:VT323,monospace;font-size:var(--fs-dense)"><span style="color:var(--gr)">Talent: </span><span style="color:'+trCol+'">'+trLabel+'</span></div>'+
              '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">×'+pr.trainRate.toFixed(2)+' ogólny</div>'+
            '</div>'+
            (arch5?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);font-style:italic">"'+arch5.desc+'"</div>':'')+
            '<div style="display:flex;gap:3px;margin-top:5px;padding-top:4px;border-top:1px solid var(--gl)">'+barHtml5+'</div>'+
          '</div>'+
          '<div style="display:flex;gap:6px">'+
            '<button onclick="acceptProspect('+pr.id+')" style="flex:1;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">✓ PRZYJMIJ</button>'+
            '<button onclick="rejectProspect('+pr.id+')" style="flex:1;background:#3d0000;border:1px solid var(--rd);color:var(--rd);font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">✗ ZWOLNIJ</button>'+
          '</div>'+
        '</div>';
      }).join('')
    :lvl>0?
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:12px;text-align:center">Juniorzy pojawią się na początku nowego sezonu.</div>'
    :
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);margin-bottom:6px">Koszt budowy: <span style="color:var(--am)">'+fmt(acadCost(0))+'</span> zł</div>'+
      '<button onclick="buildAcademy(0)" style="width:100%;background:var(--am);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-body);padding:12px;cursor:pointer">ZBUDUJ AKADEMIĘ</button>'
    );
  // Sekcja rozbudowy
  _renderAcadRozbudowaInPrzeglad();
}
function _renderAcadRozbudowaInPrzeglad(){
  const el=document.getElementById('acad-przeglad');if(!el||!G)return;
  const lvl=getAcadLvl();const rep=G.reputation||30;const lg=G.myLeague||8;
  const sec=document.createElement('div');
  sec.innerHTML=
    '<div class="fsec" style="margin:14px 0 8px">ROZBUDOWA AKADEMII</div>'+
    ACADEMY.levels.map((a,i)=>{
      if(a.ekstraOnly&&lg!==1)return'';
      const isOwned=i<lvl;const isNext=i===lvl;
      const cost=acadCost(i);const upk=acadUpkeep(i);
      const reqOk=rep>=(a.req||0);const canAfford=G.budget>=cost;
      return '<div style="background:var(--tb);border:2px solid '+(isOwned?'var(--gb)':isNext?'var(--am)':'var(--gl)')+';padding:10px 12px;margin-bottom:8px">'+
        '<div style="display:flex;justify-content:space-between;margin-bottom:6px">'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+(isOwned?'var(--gb)':isNext?'var(--am)':'var(--gr)')+'">L'+(i+1)+' — '+a.name+(a.ekstraOnly?' [Ekstra]':'')+'</div>'+
          (isOwned?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">AKTYWNA</div>':'')+
        '</div>'+
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;font-family:VT323,monospace;font-size:var(--fs-dense);margin-bottom:6px">'+
          '<div><span style="color:var(--gr)">Juniorzy: </span><span style="color:var(--wh)">'+a.perSeason+'/sez.</span></div>'+
          '<div><span style="color:var(--gr)">Max pot.: </span><span style="color:var(--am)">'+a.maxPot+'</span></div>'+
          '<div><span style="color:var(--gr)">OVR start: </span><span style="color:var(--wh)">'+(a.ovrMin||18)+'-'+a.maxPot+'</span></div>'+
          '<div><span style="color:var(--gr)">Koszt: </span><span style="color:var(--wh)">'+fmt(cost)+'</span></div>'+
          '<div><span style="color:var(--gr)">Utrzym/tyg: </span><span style="color:var(--rd)">-'+fmt(upk)+'</span></div>'+
          '<div><span style="color:var(--gr)">Czas budowy: </span><span style="color:var(--am)">'+a.buildWeeks+' tyg.</span></div>'+
          (a.req>0?'<div><span style="color:var(--gr)">Wymaga rep: </span><span style="color:'+(reqOk?'var(--gb)':'var(--rd)')+'">'+a.req+(reqOk?' OK':' brakuje '+(a.req-rep))+'</span></div>':'')+
        '</div>'+
        (!isOwned&&isNext?
          (!reqOk?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">[zablok.] Wymaga Rep '+a.req+' (masz '+rep+')</div>':
           !canAfford?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">Brakuje '+fmt(cost-G.budget)+'</div>':
           '<button onclick="buildAcademy('+i+')" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">'+(lvl===0?'ZBUDUJ':'ULEPSZ')+' — '+fmt(cost)+'</button>')
        :'')+
      '</div>';
    }).join('');
  el.appendChild(sec);
}
function renderAcadWychowankowie(){
  var el=document.getElementById('acad-wychowankowie');if(!el||!G)return;
  // Subtabs state
  if(!window._acadWychTab)window._acadWychTab='sklad';
  var tab=window._acadWychTab;
  var grads=myPl().filter(function(p){return p.fromAcademy;});
  var hist=(G.academy&&G.academy.hist)||[];
  var absolwenci=hist.filter(function(h){return !h.isRejected&&h.pid&&!myPl().find(function(p){return p.id===h.pid;})&&h.soldTo;});
  var odpuszczeni=hist.filter(function(h){return h.isRejected;});

  function mkSubTab(id,label,active){
    return '<button onclick="window._acadWychTab=\''+id+'\';renderAcadWychowankowie()" style="font-family:VT323,monospace;font-size:var(--fs-dense);padding:5px 8px;background:'+(active?'var(--gb)':'var(--tb)')+';color:'+(active?'#000':'var(--gr)')+';border:1px solid '+(active?'var(--gb)':'var(--gl)')+';cursor:pointer;text-transform:uppercase">'+label+'</button>';
  }

  var html='<div style="display:flex;gap:4px;margin-bottom:10px">'+
    mkSubTab('sklad','W składzie ('+grads.length+')',tab==='sklad')+
    mkSubTab('absolwenci','Absolwenci ('+absolwenci.length+')',tab==='absolwenci')+
    mkSubTab('odpuszczeni','Odpuszczeni ('+odpuszczeni.length+')',tab==='odpuszczeni')+
  '</div>';

  if(tab==='sklad'){
    if(grads.length){
      html+=grads.map(function(p){
        var arch9=p.archetype&&ARCHETYPE_META[p.archetype]?ARCHETYPE_META[p.archetype]:null;
        var debH9=p.history?p.history.find(function(h){return h.fromAcademy;}):null;
        var growth9=debH9?ovr(p)-debH9.ovr:0;
        var tal9=p.trainRate>=1.5?'🌟 Talent':p.trainRate>=1.1?'⚡ Szybki':'📊 Normalny';
        var talCol9=p.trainRate>=1.5?'var(--gb)':p.trainRate>=1.1?'var(--am)':'var(--wh)';
        return '<div style="background:var(--tb);border:1px solid var(--gb);padding:8px 12px;margin-bottom:4px;cursor:pointer" onclick="showById('+p.id+')">'+
          '<div style="display:flex;justify-content:space-between;margin-bottom:2px">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--wh)">🎓 '+p.name+'</div>'+
            (arch9?'<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+arch9.color+'">'+arch9.icon+' '+arch9.name+'</span>':'')+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">'+
            (POS_SHORT[p.pos]||p.pos)+' • '+p.age+'l • OVR <span style="color:var(--wh)">'+ovr(p)+'</span> • Pot: <span style="color:var(--am)">'+p.potential+'</span>'+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);margin-top:2px">'+
            '<span style="color:var(--gr)">Talent: </span><span style="color:'+talCol9+'">'+tal9+'</span>'+
            (debH9&&growth9>0?' <span style="color:var(--gr)"> • Wzrost: </span><span style="color:var(--gb)">+'+growth9+' OVR</span>':'')+ 
            (debH9?' <span style="color:var(--gr)"> od S'+debH9.season+'</span>':'')+
          '</div>'+
        '</div>';
      }).join('');
    } else {
      html+='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:12px;text-align:center">Brak wychowanków w składzie</div>';
    }
  } else if(tab==='absolwenci'){
    if(absolwenci.length){
      html+=absolwenci.slice().reverse().map(function(h){
        var arch9b=h.archetype&&ARCHETYPE_META[h.archetype]?ARCHETYPE_META[h.archetype]:null;
        return '<div style="background:var(--tb);border:1px solid var(--gl);padding:8px 12px;margin-bottom:4px">'+
          '<div style="display:flex;justify-content:space-between;margin-bottom:2px">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">🎓 '+h.name+' <span style="font-size:var(--fs-dense);color:#555">(odszedł)</span></div>'+
            (arch9b?'<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+arch9b.color+'">'+arch9b.icon+' '+arch9b.name+'</span>':'')+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">'+
            h.pos+
            (h.joinedSeason?' • dołączył S'+h.joinedSeason:'')+
            (h.peakOvr?' • Szczyt OVR: <span style="color:var(--am)">'+h.peakOvr+'</span>':'')+
          '</div>'+
          (h.soldTo?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);margin-top:2px"><span style="color:var(--gr)">Sprzedany do: </span><span style="color:var(--wh)">'+h.soldTo+'</span>'+(h.fee?' <span style="color:var(--gb)">za '+fmtVal(h.fee)+'</span>':'')+'</div>':'')+
        '</div>';
      }).join('');
    } else {
      html+='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:12px;text-align:center">Żaden wychowanek jeszcze nie odszedł.</div>';
    }
  } else if(tab==='odpuszczeni'){
    if(odpuszczeni.length){
      html+=odpuszczeni.slice().reverse().map(function(h){
        var arch9c=h.archetype&&ARCHETYPE_META[h.archetype]?ARCHETYPE_META[h.archetype]:null;
        return '<div style="background:var(--tb);border:1px solid #3d0000;padding:8px 12px;margin-bottom:4px">'+
          '<div style="display:flex;justify-content:space-between;margin-bottom:2px">'+
            '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:#888">🎓 '+h.name+' <span style="color:var(--rd);font-size:9px">✗ zwolniony</span></div>'+
            (arch9c?'<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+arch9c.color+'">'+arch9c.icon+' '+arch9c.name+'</span>':'')+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">'+
            h.pos+' • S'+h.season+
            (h.releaseOvr?' • OVR przy zwolnieniu: <span style="color:#888">'+h.releaseOvr+'</span>':'')+
            (h.pot?' • Pot było: <span style="color:var(--am)">'+h.pot+'</span>':'')+
          '</div>'+
          '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:#555;margin-top:3px;font-style:italic">Czy to była dobra decyzja?</div>'+
        '</div>';
      }).join('');
    } else {
      html+='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);padding:12px;text-align:center">Żaden junior nie został odpuszczony.</div>';
    }
  }

  el.innerHTML=html;
}
function renderAcadHistoryTab(p){
  var el=document.getElementById('plr-acad-content');if(!el)return;
  var arch=p.archetype&&ARCHETYPE_META[p.archetype]?ARCHETYPE_META[p.archetype]:null;
  var hist=(p.history||[]).filter(function(h){return !h._placeholder;}).sort(function(a,b){return a.season-b.season;});
  var acadDebH=hist.find(function(h){return h.fromAcademy;})||hist[0];
  var curOvr=ovr(p);
  var debOvr=acadDebH?acadDebH.ovr:curOvr;
  var debSzn=acadDebH?acadDebH.season:G.season;
  var seasonsInClub=hist.filter(function(h){return h.clubId===G.myClubId;}).length;
  var totalM=hist.reduce(function(s,h){return s+(h.m||0);},0);
  var totalG=hist.reduce(function(s,h){return s+(h.g||0);},0);
  var totalA=hist.reduce(function(s,h){return s+(h.a||0);},0);
  var growth=curOvr-debOvr;
  // Znajdź % składu słabszych na debiucie
  var myPls=myPl();
  var betterThanOnDebut=myPls.filter(function(x){return ovr(x)>debOvr;}).length;
  var pctWeak=myPls.length>0?Math.round((betterThanOnDebut/myPls.length)*100):0;
  var rankNow=[...myPls].sort(function(a,b){return ovr(b)-ovr(a);}).findIndex(function(x){return x.id===p.id;})+1;

  var html='';
  // Nagłówek wychowanka
  html+='<div style="background:#0a1f0a;border:2px solid #9c27b0;padding:10px 12px;margin-bottom:10px">'+
    '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:#ce93d8;margin-bottom:4px">🎓 WYCHOWANEK AKADEMII</div>'+
    '<div style="display:flex;gap:6px;flex-wrap:wrap">'+
      (arch?'<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+arch.color+';border:1px solid '+arch.color+';padding:1px 5px">'+arch.icon+' '+arch.name+'</span>':'')+
      '<span style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb);border:1px solid var(--gb);padding:1px 5px">W Akademii od S'+debSzn+'</span>'+
    '</div>'+
  '</div>';

  // Statystyki kluczowe
  html+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;margin-bottom:10px">'+
    '<div style="background:var(--tb);border:1px solid var(--gl);padding:8px 4px;text-align:center">'+
      '<div style="font-family:VT323,monospace;font-size:'+(growth>0?'16px':'12px')+';color:'+(growth>0?'var(--gb)':'var(--gr)')+'">+'+(growth>0?growth:0)+'</div>'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">wzrost OVR</div>'+
    '</div>'+
    '<div style="background:var(--tb);border:1px solid var(--gl);padding:8px 4px;text-align:center">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-body);color:var(--am)">'+seasonsInClub+'</div>'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">sez. u nas</div>'+
    '</div>'+
    '<div style="background:var(--tb);border:1px solid var(--gl);padding:8px 4px;text-align:center">'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-body);color:var(--wh)">'+totalM+'</div>'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">mecze</div>'+
    '</div>'+
  '</div>';

  // Porównanie
  if(myPls.length>1){
    html+='<div style="background:var(--tb);border:1px solid var(--gl);padding:8px 10px;margin-bottom:10px;font-family:VT323,monospace;font-size:var(--fs-dense)">'+
      '<span style="color:var(--gr)">Na debiucie był gorszy od </span><span style="color:var(--rd)">'+pctWeak+'% składu</span>'+
      (rankNow>0?'<span style="color:var(--gr)">. Dziś jest </span><span style="color:var(--gb)">'+(rankNow===1?'najlepszym':''+rankNow+'.')+'</span><span style="color:var(--gr)"> zawodnikiem drużyny</span>':'')+'.'+
    '</div>';
  }

  // Oś czasu sezonów
  html+='<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr);letter-spacing:1px;border-bottom:1px solid var(--gl);padding-bottom:3px;margin-bottom:8px">OŚ CZASU</div>';
  var allHist=(p.history||[]).filter(function(h){return !h._placeholder;}).sort(function(a,b){return a.season-b.season;});
  allHist.forEach(function(h,i){
    var isFirst=i===0;
    var prevH=i>0?allHist[i-1]:null;
    var ovrGrowth=prevH&&h.ovr&&prevH.ovr?(h.ovr-prevH.ovr):0;
    var isHighlight=isFirst||(ovrGrowth>=8)||(h.g>=5)||(h.fromAcademy&&isFirst);
    var borderCol=isHighlight?'var(--gb)':'var(--gl)';
    // Autodetekcja eventu
    var noteIcon='';
    if(isFirst&&h.fromAcademy)noteIcon='🎓 Przyjęty z Akademii';
    else if(h.m>0&&prevH&&(prevH.m||0)===0)noteIcon='⚡ Debiut w składzie';
    else if(h.g>=5)noteIcon='🔥 Świetny sezon strzelecki';
    else if(ovrGrowth>=10)noteIcon='📈 Przełomowy sezon (+'+ovrGrowth+' OVR)';
    html+='<div style="background:'+(isHighlight?'#0d2b0d':'var(--tb)')+';border:1px solid '+borderCol+';padding:8px 10px;margin-bottom:4px">'+
      '<div style="display:flex;justify-content:space-between;margin-bottom:2px">'+
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+(isHighlight?'var(--gb)':'var(--wh)')+'">S'+h.season+' — OVR '+(h.ovr||'?')+'</div>'+
        (ovrGrowth>0?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">+'+ovrGrowth+' OVR</div>':'')+
      '</div>'+
      '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gr)">'+
        (h.m||0)+' meczów'+(h.g?(' • '+(h.g||0)+' goli'):'')+((h.a||0)>0?(' • '+(h.a||0)+' asyst'):'')+
        (h.club?' • <span style="color:var(--am)">'+h.club+'</span>':'')+
      '</div>'+
      (noteIcon?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--am);margin-top:3px">'+noteIcon+'</div>':'')+
    '</div>';
  });

  el.innerHTML=html;
}

function renderAcadRozbudowa(){
  const el=document.getElementById('acad-rozbudowa');if(!el||!G)return;
  const lvl=getAcadLvl();const rep=G.reputation||30;const lg=G.myLeague||8;
  el.innerHTML=ACADEMY.levels.map((a,i)=>{
    if(a.ekstraOnly&&lg!==1)return'';
    const isOwned=i<lvl;const isNext=i===lvl;
    const cost=acadCost(i);const upk=acadUpkeep(i);
    const reqOk=rep>=(a.req||0);const canAfford=G.budget>=cost;
    return '<div style="background:var(--tb);border:2px solid '+(isOwned?'var(--gb)':isNext?'var(--am)':'var(--gl)')+';padding:10px 12px;margin-bottom:8px">'+
      '<div style="display:flex;justify-content:space-between;margin-bottom:6px">'+
        '<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:'+(isOwned?'var(--gb)':isNext?'var(--am)':'var(--gr)')+'">L'+(i+1)+' — '+a.name+(a.ekstraOnly?' [Ekstra]':'')+'</div>'+
        (isOwned?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--gb)">AKTYWNA</div>':'')+
      '</div>'+
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;font-family:VT323,monospace;font-size:var(--fs-dense);margin-bottom:6px">'+
        '<div><span style="color:var(--gr)">Juniorzy: </span><span style="color:var(--wh)">'+a.perSeason+'/sez.</span></div>'+
        '<div><span style="color:var(--gr)">Max pot.: </span><span style="color:var(--am)">'+a.maxPot+'</span></div>'+
        '<div><span style="color:var(--gr)">OVR start: </span><span style="color:var(--wh)">'+(a.ovrMin||18)+'-'+a.maxPot+'</span></div>'+
        '<div><span style="color:var(--gr)">Koszt: </span><span style="color:var(--wh)">'+fmt(cost)+'</span></div>'+
        '<div><span style="color:var(--gr)">Utrzym/tyg: </span><span style="color:var(--rd)">-'+fmt(upk)+'</span></div>'+
        '<div><span style="color:var(--gr)">Czas budowy: </span><span style="color:var(--am)">'+a.buildWeeks+' tyg.</span></div>'+
        (a.req>0?'<div><span style="color:var(--gr)">Wymaga rep: </span><span style="color:'+(reqOk?'var(--gb)':'var(--rd)')+'">'+a.req+(reqOk?' OK':' brakuje '+(a.req-rep))+'</span></div>':'')+
        (a.ekstraOnly?'<div><span style="color:var(--gr)">Liga: </span><span style="color:var(--am)">Tylko Premier Division</span></div>':a.req>=500?'<div><span style="color:var(--gr)">Dostępna od: </span><span style="color:var(--wh)">I Ligi (rep 500+)</span></div>':a.req>=250?'<div><span style="color:var(--gr)">Dostępna od: </span><span style="color:var(--wh)">III Ligi (rep 250+)</span></div>':a.req>=100?'<div><span style="color:var(--gr)">Dostępna od: </span><span style="color:var(--wh)">V Ligi (rep 100+)</span></div>':'')+
      '</div>'+
      (!isOwned&&isNext?
        (!reqOk?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">[zablok.] Wymaga Rep '+a.req+' (masz '+rep+')</div>':
         !canAfford?'<div style="font-family:VT323,monospace;font-size:var(--fs-dense);color:var(--rd)">Brakuje '+fmt(cost-G.budget)+'</div>':
         '<button onclick="buildAcademy('+i+')" style="width:100%;background:var(--gb);color:#000;border:none;font-family:VT323,monospace;font-size:var(--fs-meta);padding:8px;cursor:pointer">'+(lvl===0?'ZBUDUJ':'ULEPSZ')+' — '+fmt(cost)+'</button>')
      :'')+
    '</div>';
  }).join('');
}
function buildAcademy(levelIdx){
  if(!G)return;
  if(!G.academy)G.academy={level:0,prospects:[],hist:[]};
  const a=ACADEMY.levels[levelIdx];if(!a)return;
  if(a.ekstraOnly&&(G.myLeague||8)!==1){notif('Akademia Mistrzów tylko dla Ekstraklasy!','err');return;}
  const _cst=acadCost(levelIdx);
  if(G.budget<_cst){notif('Za mało środków!','err');return;}
  if((G.reputation||30)<(a.req||0)){notif('Wymaga Reputacji '+a.req+'!','err');return;}
  G.budget-=_cst;
  if(!G.fin.hist)G.fin.hist=[];
  G.fin.hist.push({w:G.week,inc:0,cost:_cst,bal:G.budget,season:G.season,note:'Akademia: '+a.name});
  const _bw=a.buildWeeks||4;
  G.academy.building={levelIdx:levelIdx+1,weeksLeft:_bw,name:a.name};
  addNews(t('news_academy_build').replace('{name}',a.name).replace('{n}',_bw),'academy');
  notif('Budowa '+a.name+' (+'+_bw+' tyg)','ok');
  renderAcadPrzeglad();
}
function acceptProspect(pid){
  if(!G||!G.academy)return;
  const pr=G.academy.prospects.find(x=>x.id===pid);if(!pr)return;
  pr.status='accepted';
  const p=mkPlayer(G.myClubId);
  p.id=pr.id;p.name=pr.name;p.last=pr.name.split(' ')[1]||pr.name;
  p.pos=pr.pos;p.age=pr.age;p.trainRate=pr.trainRate;p.trainMatches=0;
  p.potential=pr.potential;p.fromAcademy=true;p.archetype=pr.archetype||null;
  ['tec','pas','sht','def','phy','men'].forEach(a=>{p[a]=Math.max(1,Math.min(99,Math.round(pr.ovr+r(-5,5))));});
  p.value=calcValue(ovr(p),p.age);p.salary=calcSalary(p.value,G.myLeague,ovr(p));
  p.contract=3;p.starter=false;
  assignJerseyNum(p);
  G.players.push(p);
  G.academy.hist.push({pid:p.id,season:G.season,name:pr.name,pos:POS_SHORT[pr.pos]||pr.pos,action:'Dołączył do składu',joinedSeason:G.season,archetype:pr.archetype||null,startOvr:pr.ovr,pot:pr.potential});
  addNews(t('news_academy_joined').replace('{name}',pr.name).replace('{pot}',pr.potential),'academy');
  notif(pr.name+' dołączył!','ok');
  renderAcadPrzeglad();renderAcadWychowankowie();
}
function rejectProspect(pid){
  if(!G||!G.academy)return;
  const pr=G.academy.prospects.find(x=>x.id===pid);if(!pr)return;
  pr.status='rejected';
  G.academy.hist.push({season:G.season,name:pr.name,pos:POS_SHORT[pr.pos]||pr.pos,action:'Odpuszczony (junior)',releaseOvr:pr.ovr,pot:pr.potential,archetype:pr.archetype||null,isRejected:true});
  notif(pr.name+' zwolniony','ok');
  renderAcadPrzeglad();
}
function generateProspects(){
  if(!G||!G.academy||G.academy.level===0)return;
  const lvl=getAcadLvl();const acad=ACADEMY.levels[lvl-1];if(!acad)return;
  if(!G.academy.prospects)G.academy.prospects=[];
  G.academy.prospects=G.academy.prospects.filter(p=>p.status!=='pending');
  const pos=['GK','OBR','OBR','POL','POL','NAP','NAP','OBR'];
  for(let i=0;i<acad.perSeason;i++){
    const trRoll=Math.random();
    const trainRate=trRoll<0.10?(50+r(0,30))/100:trRoll<0.45?(81+r(0,29))/100:trRoll<0.75?(110+r(0,40))/100:(150+r(0,50))/100;
    const baseOvr=r(10,25);
    const potential=Math.min(acad.maxPot,baseOvr+r(20,acad.maxPot-baseOvr));
    const _arch4=['wojownik','techniczny','snajper','lider'][Math.floor(Math.random()*4)];
    G.academy.prospects.push({id:pid++,name:getUniqueName(),pos:pos[Math.floor(Math.random()*pos.length)],age:r(16,17),ovr:baseOvr,potential,trainRate,archetype:_arch4,status:'pending'});
  }
  if(!G.news)G.news=[];
  G.news.unshift({msg:'🎓 Akademia wykształciła '+acad.perSeason+' nowych juniora! Oceń ich i zdecyduj kogo przyjąć.',type:'ok',week:G.week,season:G.season,action:'academy',actionLabel:'AKADEMIA'});
  renderNews();
}


